import { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  orderBy,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  setDoc,
  getDoc,
  arrayUnion,
  writeBatch,
  getDocs
} from 'firebase/firestore';
import { DBItem, MapSector, PartRequest, BOMRequest, BOMComponent } from '../../types/appTypes';

export const useMasterData = () => {
  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, BOMComponent[]>>({});
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]);
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);

  useEffect(() => {
    const unsubWp = onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubLogOps = onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), s => setLogisticsOperations(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubSectors = onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
        const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
        setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0)));
    });
    const unsubPartReq = onSnapshot(collection(db, 'part_requests'), s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest))));
    const unsubBomReq = onSnapshot(collection(db, 'bom_requests'), s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest))));

    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (docSnap) => {
        const cleanMap: Record<string, string> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.value) cleanMap[item.value] = item.description || '';
                });
            }
        }
        setPartsMap(cleanMap);
    });

    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (docSnap) => {
        const cleanMap: Record<string, BOMComponent[]> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.parent && item.child) {
                        if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                        cleanMap[item.parent].push({ child: item.child, consumption: item.consumption || 0 });
                    }
                });
            }
        }
        setBomMap(cleanMap);
    });

    return () => { 
        unsubWp(); unsubLogOps(); unsubSectors(); unsubPartReq(); unsubBomReq();
        unsubParts(); unsubBOM();
    };
  }, []);

  // --- ACTIONS ---

  // Workplaces
  const onAddWorkplace = async (val: string, time: number = 0, x: number = 0, y: number = 0) => {
      await addDoc(collection(db, 'workplaces'), { value: val, standardTime: time, coordX: x, coordY: y });
  };
  const onUpdateWorkplace = async (id: string, updates: Partial<DBItem>) => {
      await updateDoc(doc(db, 'workplaces', id), updates);
  };
  const onDeleteWorkplace = async (id: string) => {
      await deleteDoc(doc(db, 'workplaces', id));
  };
  const onDeleteAllWorkplaces = async () => {
      const snap = await getDocs(collection(db, 'workplaces'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };
  const onBatchAddWorkplaces = async (vals: string[]) => {
      const batch = writeBatch(db);
      vals.forEach(line => {
          if (!line.trim()) return;
          const [val, time] = line.split(';');
          const ref = doc(collection(db, 'workplaces'));
          batch.set(ref, { value: val.trim(), standardTime: parseInt(time) || 0 });
      });
      await batch.commit();
  };

  // Logistics Operations
  const onAddLogisticsOperation = async (val: string, time: number = 0, dist: number = 0, x: number = 0, y: number = 0) => { await addDoc(collection(db, 'logistics_operations'), { value: val, standardTime: time, distancePx: dist, coordX: x, coordY: y }); };
  const onUpdateLogisticsOperation = async (id: string, updates: Partial<DBItem>) => { await updateDoc(doc(db, 'logistics_operations', id), updates); };
  const onDeleteLogisticsOperation = async (id: string) => { await deleteDoc(doc(db, 'logistics_operations', id)); };
  const onDeleteAllLogisticsOperations = async () => {
      const snap = await getDocs(collection(db, 'logistics_operations'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };

  // Map Sectors
  const onAddMapSector = async (name: string, x: number, y: number, color?: string) => { await addDoc(collection(db, 'map_sectors'), { name, coordX: x, coordY: y, color }); };
  const onUpdateMapSector = async (id: string, updates: Partial<MapSector>) => { await updateDoc(doc(db, 'map_sectors', id), updates); };
  const onDeleteMapSector = async (id: string) => { await deleteDoc(doc(db, 'map_sectors', id)); };

  // Parts (Single Doc Pattern)
  const onAddPart = async (value: string, description: string = '') => {
      try {
          const newItem = { id: `part_${Date.now()}_${Math.random().toString(36).substr(2,9)}`, value: value.toUpperCase(), description, createdAt: Date.now() };
          await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddParts = async (vals: string[]) => {
    try {
      const itemsToAdd: any[] = [];
      vals.forEach((valLine) => {
        if (!valLine.trim()) return;
        const [p, d] = valLine.split(';');
        if(p) { itemsToAdd.push({ id: `part_${Date.now()}_${Math.random().toString(36).substr(2,9)}_${itemsToAdd.length}`, value: p.trim().toUpperCase(), description: d ? d.trim() : '', createdAt: Date.now() }); }
      });
      if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
    } catch (error) { console.error("Error batch adding parts:", error); throw error; }
  };
  const onDeletePart = async (val: string) => {
      try {
          const ref = doc(db, 'settings', 'parts');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => i.value !== val);
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error("Error deleting part:", e); }
  };
  const onDeleteAllParts = async () => { try { await setDoc(doc(db, 'settings', 'parts'), { items: [] }); } catch (e) { console.error("Error clearing parts:", e); } };

  // BOM (Single Doc Pattern - Optimized for Quota Guard)
  const onAddBOMItem = async (parent: string, child: string, qty: number) => {
      try {
          // Ukladáme len nevyhnutné polia pre výpočet spotreby
          const newItem = { 
              parent: parent.toUpperCase(), 
              child: child.toUpperCase(), 
              consumption: qty 
          };
          await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddBOMItems = async (vals: string[]) => {
      try {
          const itemsToAdd: any[] = [];
          vals.forEach(line => {
              if (!line.trim()) return;
              const [p, c, q] = line.split(';');
              if (p && c) { 
                  itemsToAdd.push({ 
                      parent: p.trim().toUpperCase(), 
                      child: c.trim().toUpperCase(), 
                      consumption: parseFloat(q?.replace(',', '.') || '0') 
                  }); 
              }
          });
          if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
      } catch (e) { console.error(e); }
  };
  const onDeleteBOMItem = async (parent: string, child: string) => {
      try {
          const ref = doc(db, 'settings', 'bom');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => !(i.parent === parent && i.child === child));
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error(e); }
  };
  const onDeleteAllBOMItems = async () => { try { await setDoc(doc(db, 'settings', 'bom'), { items: [] }); } catch (e) { console.error(e); } };

  // Requests
  const onRequestPart = async (part: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'part_requests'), { partNumber: part, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeletePartRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'part_requests', id)); } catch(e) { console.error(e); }
  };

  const onRequestBOM = async (parent: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'bom_requests'), { parentPart: parent, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeleteBOMRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'bom_requests', id)); } catch(e) { console.error(e); }
  };

  return {
    partsMap, bomMap, workplaces, logisticsOperations, mapSectors, partRequests, bomRequests,
    onAddWorkplace, onUpdateWorkplace, onDeleteWorkplace, onDeleteAllWorkplaces, onBatchAddWorkplaces,
    onAddLogisticsOperation, onUpdateLogisticsOperation, onDeleteLogisticsOperation, onDeleteAllLogisticsOperations,
    onAddMapSector, onUpdateMapSector, onDeleteMapSector,
    onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts,
    onAddBOMItem, onBatchAddBOMItems, onDeleteBOMItem, onDeleteAllBOMItems,
    onRequestPart, onDeletePartRequest, 
    onRequestBOM, onDeleteBOMRequest
  };
};

import React, { useState } from 'react';
import { Role, Permission } from '../../App'; 
import { useLanguage } from '../LanguageContext';

interface PermissionsTabProps {
    roles: Role[];
    permissions: Permission[];
    onAddRole: (name: string, parentId?: string, rank?: number) => void;
    onDeleteRole: (id: string) => void;
    onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
    onVerifyAdminPassword: (password: string) => boolean;
}

const PermissionsTab: React.FC<PermissionsTabProps> = ({ roles, permissions, onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword }) => {
    const { t, language } = useLanguage();
    const [newRoleName, setNewRoleName] = useState('');
    const [selectedParentId, setSelectedParentId] = useState('');

    const permGroups = [
      {
          name: 'perm_group_tabs',
          perms: [
              'perm_tab_entry', 
              'perm_tab_tasks', 
              'perm_tab_bom', 
              'perm_tab_missing', 
              'perm_tab_inventory', 
              'perm_tab_logistics_center', 
              'perm_tab_map', // PRIDANÉ: Oprávnenie pre mapu
              'perm_tab_analytics', 
              'perm_tab_settings', 
              'perm_tab_permissions', 
              'perm_logistics_mode'
          ] 
      },
      {
          name: 'perm_group_actions',
          perms: ['perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_return', 'perm_btn_note', 'perm_btn_incorrect', 'perm_btn_lock', 'perm_btn_block_new', 'perm_btn_audit', 'perm_view_fullscreen', 'perm_play_sound', 'perm_push_notification', 'perm_view_passwords']
      },
      {
          name: 'perm_group_settings',
          perms: ['perm_view_setup', 'perm_settings_users', 'perm_settings_parts', 'perm_settings_wp', 'perm_settings_bom', 'perm_settings_system', 'perm_settings_maint']
      },
      {
          name: 'perm_group_mgmt',
          perms: ['perm_manage_users', 'perm_delete_users', 'perm_manage_db', 'perm_manage_logistics_ops', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'] 
      }
    ];

    const hasPermission = (roleId: string, permName: string) => {
        return permissions?.some(p => p.roleId === roleId && p.permissionName === permName) || false;
    };

    const handleCreateRole = () => {
        if (!newRoleName.trim()) return;
        const parent = roles.find(r => r.id === selectedParentId);
        const rank = parent ? (parent.rank || 0) + 1 : 5;
        onAddRole(newRoleName, selectedParentId || undefined, rank);
        setNewRoleName('');
        setSelectedParentId('');
    };

    const canDelete = (role: Role) => !role.isSystem && role.name.toUpperCase() !== 'ADMIN';

    const handleDeleteClick = (role: Role) => {
        if (!canDelete(role)) return;
        if (window.confirm(language === 'sk' ? `Naozaj chcete vymazať rolu ${role.name}?` : `Delete role ${role.name}?`)) {
            onDeleteRole(role.id);
        }
    };

    return (
        <div className="max-w-6xl mx-auto space-y-10 pb-12 animate-fade-in relative">
            <h1 className="text-center text-3xl font-extrabold text-orange-400 mb-8 uppercase tracking-widest">{t('sect_roles')}</h1>

            {/* Role Management Header */}
            <div className="bg-gray-800 p-6 rounded-2xl border border-gray-700 shadow-xl mb-10">
                <h3 className="text-xs font-black text-gray-500 uppercase tracking-[0.2em] mb-4">Vytvoriť novú rolu</h3>
                <div className="flex flex-col md:flex-row gap-4">
                    <input 
                        type="text" 
                        value={newRoleName}
                        onChange={(e) => setNewRoleName(e.target.value)}
                        placeholder={t('role_name_place')}
                        className="flex-1 bg-gray-900 border border-gray-700 text-white px-5 py-3 rounded-xl focus:border-orange-500 outline-none font-bold uppercase placeholder-gray-600"
                    />
                    <select 
                        value={selectedParentId}
                        onChange={(e) => setSelectedParentId(e.target.value)}
                        className="md:w-64 bg-gray-900 border border-gray-700 text-white px-5 py-3 rounded-xl focus:border-orange-500 outline-none font-bold uppercase"
                    >
                        <option value="">{language === 'sk' ? 'ŽIADNY NADRIADENÝ' : 'NO PARENT ROLE'}</option>
                        {roles.map(r => (
                            <option key={r.id} value={r.id}>{r.name} (LVL {r.rank || 0})</option>
                        ))}
                    </select>
                    <button 
                        onClick={handleCreateRole}
                        className="bg-orange-600 hover:bg-orange-500 text-white font-black px-10 py-3 rounded-xl transition-all shadow-lg active:scale-95 uppercase tracking-widest text-sm"
                    >
                        {t('role_add_btn')}
                    </button>
                </div>
            </div>

            {permGroups.map(group => (
                 <div key={group.name} className="bg-gray-900 rounded-2xl p-8 border border-gray-700">
                     <h3 className="text-xl font-black text-gray-300 mb-6 border-b border-gray-700 pb-3 uppercase">{t(group.name as any)}</h3>
                     <div className="overflow-x-auto custom-scrollbar"> 
                         <table className="min-w-[700px] w-full text-left text-base">
                             <thead>
                                 <tr>
                                     <th className="py-4 px-5 text-gray-400 font-bold uppercase text-xs tracking-widest">{t('permission_label')}</th> 
                                     {roles.map(role => (
                                         <th key={role.id} className="py-4 px-5 text-white font-black text-center min-w-[120px]">
                                             <div className="flex flex-col items-center gap-1">
                                                 <span className="text-sm leading-tight">{role.name}</span>
                                                 <div className="flex items-center gap-2">
                                                     <span className="text-[9px] text-orange-500/70 uppercase font-black bg-orange-500/10 px-1.5 rounded border border-orange-500/20">LVL {role.rank || 0}</span>
                                                     <button 
                                                        onClick={() => handleDeleteClick(role)}
                                                        disabled={!canDelete(role)}
                                                        className={`transition-colors ${canDelete(role) ? 'text-gray-600 hover:text-red-500' : 'text-gray-800 cursor-not-allowed opacity-30'}`}
                                                     >
                                                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                                     </button>
                                                 </div>
                                             </div>
                                         </th>
                                     ))}
                                 </tr>
                             </thead>
                             <tbody className="divide-y divide-gray-800">
                                 {group.perms.map(perm => (
                                     <tr key={perm} className="hover:bg-gray-800/50 transition-colors">
                                         <td className="py-5 px-5 text-gray-300 font-medium">{t(perm as any)}</td>
                                         {roles.map(role => (
                                             <td key={`${role.id}-${perm}`} className="py-5 px-5 text-center">
                                                 <input 
                                                    type="checkbox" 
                                                    checked={hasPermission(role.id, perm)} 
                                                    onChange={(e) => onUpdatePermission && onUpdatePermission(perm, role.name, e.target.checked)} 
                                                    className="w-6 h-6 text-orange-500 bg-gray-700 border-gray-600 rounded cursor-pointer transition-transform active:scale-110" 
                                                 />
                                             </td>
                                         ))}
                                     </tr>
                                 ))}
                             </tbody>
                         </table>
                     </div>
                 </div>
             ))}
        </div>
    );
};

export default PermissionsTab;

import React, { useState, useEffect, useRef, useMemo, memo } from 'react';
import { useLanguage } from './LanguageContext';
import { db } from '../firebase';
import { doc, getDoc } from 'firebase/firestore';

interface PartNumberInputProps {
  parts: string[];
  onPartSelect: (part: string | null) => void;
  onInputChange?: (value: string) => void;
  placeholder?: string;
  value: string | null;
  onRequestPart?: (part: string) => Promise<boolean>;
  inputRef?: React.RefObject<HTMLInputElement>;
  onKeyDown?: React.KeyboardEventHandler<HTMLInputElement>;
}

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
    </svg>
);

const PlusIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
  </svg>
);

const GlobeIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9" />
    </svg>
);

const PartNumberInput: React.FC<PartNumberInputProps> = memo(({ parts, onPartSelect, onInputChange, placeholder, value, onRequestPart, inputRef, onKeyDown }) => {
  const [query, setQuery] = useState<string>('');
  const [isDropdownVisible, setIsDropdownVisible] = useState<boolean>(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const { t, language } = useLanguage();

  const [reportStatus, setReportStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [masterSearchStatus, setMasterSearchStatus] = useState<'idle' | 'loading' | 'found' | 'not_found'>('idle');

  useEffect(() => {
    setQuery(value || '');
  }, [value]);

  const filteredParts = useMemo(() => {
    const trimmedQuery = query.trim();
    if (trimmedQuery === '') return parts.slice(0, 50);

    const q = trimmedQuery.toLowerCase();
    // Wildcard search support
    if (q.includes('*')) {
      const regexStr = q.replace(/\*/g, '.*');
      const regex = new RegExp(`^${regexStr}`, 'i');
      return parts.filter(p => regex.test(p)).slice(0, 50);
    }

    return parts.filter(p => p.toLowerCase().includes(q)).slice(0, 50);
  }, [query, parts]);

  useEffect(() => {
    setReportStatus('idle');
    setMasterSearchStatus('idle');
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsDropdownVisible(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSelectPart = (part: string) => {
    setQuery(part);
    onPartSelect(part);
    if (onInputChange) onInputChange(part);
    setIsDropdownVisible(false);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = e.target.value;
    setQuery(newValue);
    if (onInputChange) onInputChange(newValue);

    const exactMatch = parts.find(p => p.toLowerCase() === newValue.trim().toLowerCase());
    if (exactMatch) {
      onPartSelect(exactMatch);
    } else {
      onPartSelect(null);
    }
  };

  const handleInternalKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      setIsDropdownVisible(false);
    }
    if (onKeyDown) onKeyDown(e);
  };

  const handleRequestClick = async (e: React.MouseEvent) => {
    e.preventDefault();
    if (onRequestPart && query.trim()) {
        setReportStatus('loading');
        const success = await onRequestPart(query.trim());
        if (success) {
            setReportStatus('success');
            setIsDropdownVisible(false);
            setTimeout(() => setReportStatus('idle'), 3000);
        } else {
            setReportStatus('idle');
        }
    }
  };

  // --- NOVINKA: Master DB Lookup ---
  const handleMasterLookup = async (e: React.MouseEvent) => {
      e.preventDefault();
      const partToFind = query.trim().toUpperCase();
      if (!partToFind) return;

      setMasterSearchStatus('loading');
      try {
          // Načítame master katalóg
          const masterRef = doc(db, 'settings', 'master_catalog');
          const snap = await getDoc(masterRef);

          if (snap.exists()) {
              const data = snap.data();
              const allMasterParts = (data.parts || []) as {p: string, d: string}[];
              const found = allMasterParts.find(m => m.p.toUpperCase() === partToFind);

              if (found) {
                  setMasterSearchStatus('found');
                  if (window.confirm(t('db_master_found'))) {
                      // Automatický import cez callback (cez PartSearchScreen -> onAddPart)
                      // Pre zjednodušenie tu len nastavíme hodnotu
                      handleSelectPart(found.p);
                  }
              } else {
                  setMasterSearchStatus('not_found');
              }
          } else {
              setMasterSearchStatus('not_found');
          }
      } catch (err) {
          console.error("Master lookup failed", err);
          setMasterSearchStatus('not_found');
      }
  };

  const isExactMatch = useMemo(() => parts.some(p => p.toLowerCase() === query.trim().toLowerCase()), [query, parts]);
  const hasWildcard = query.includes('*');
  const showMasterLookup = query.trim() !== '' && !isExactMatch && !hasWildcard && masterSearchStatus === 'idle';
  const showReportButton = onRequestPart && query.trim() !== '' && !isExactMatch && !hasWildcard && masterSearchStatus === 'not_found';

  return (
    <div className="relative" ref={containerRef}>
      <div className="relative">
        <span className="absolute inset-y-0 left-0 flex items-center pl-4">
          <SearchIcon className="h-5 w-5 text-gray-500" />
        </span>
        <input
          type="text"
          ref={inputRef}
          value={query}
          onChange={handleChange}
          onKeyDown={handleInternalKeyDown}
          onFocus={() => setIsDropdownVisible(true)}
          placeholder={placeholder || t('input_wildcard_hint')}
          className="w-full h-12 pl-12 pr-4 bg-gray-700 border border-gray-600 rounded-lg text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-base"
        />
      </div>

      {isDropdownVisible && filteredParts.length > 0 && (
        <div className="absolute z-[999] w-full mt-2 bg-gray-800 border border-gray-700 rounded-lg shadow-2xl max-h-60 overflow-y-auto">
          <ul className="divide-y divide-gray-700">
            {filteredParts.map((part, index) => (
              <li
                key={index}
                onClick={() => handleSelectPart(part)}
                className="px-4 py-3 text-gray-300 hover:bg-teal-600 hover:text-white cursor-pointer transition-colors duration-150 font-mono text-base font-bold"
              >
                {part}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Tlačidlo pre Master DB Lookup */}
      {showMasterLookup && (
          <div className="mt-2 animate-fade-in">
              <button
                type="button"
                onMouseDown={handleMasterLookup}
                disabled={masterSearchStatus === 'loading'}
                className="w-full py-3 px-4 bg-indigo-600/20 border border-indigo-500/50 hover:bg-indigo-600/40 text-indigo-400 font-bold rounded-lg flex items-center justify-center gap-2 transition-all active:scale-95"
              >
                  {masterSearchStatus === 'loading' ? (
                      <div className="w-4 h-4 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin"></div>
                  ) : <GlobeIcon className="w-4 h-4" />}
                  <span className="text-xs uppercase tracking-widest">{t('db_master_lookup')}</span>
              </button>
          </div>
      )}

      {showReportButton && (
        <div className="mt-2 animate-fade-in">
             <button
                type="button"
                onMouseDown={handleRequestClick}
                disabled={reportStatus !== 'idle'}
                className={`w-full py-4 px-4 font-bold rounded-lg shadow-md flex items-center justify-center gap-2 transition-all duration-200 hover:scale-[1.01] ${
                    reportStatus === 'success' 
                    ? 'bg-green-600 border border-green-500 text-white cursor-default' 
                    : reportStatus === 'loading'
                    ? 'bg-yellow-800 border border-yellow-700 text-yellow-200 cursor-wait'
                    : 'bg-yellow-700 hover:bg-yellow-600 border border-yellow-500 text-white'
                }`}
            >
                {reportStatus === 'loading' ? (
                     <span className="text-base">{t('report_btn_loading')}</span>
                ) : reportStatus === 'success' ? (
                     <span className="text-base">{t('report_btn_success')}</span>
                ) : (
                    <>
                        <PlusIcon className="w-6 h-6 text-yellow-200" />
                        <span className="text-base">{t('report_btn_idle')} <strong>{query}</strong></span>
                    </>
                )}
            </button>
            <p className="text-center text-sm text-gray-500 mt-2">
                {reportStatus === 'success' ? t('report_hint_success') : t('report_hint_idle')}
            </p>
        </div>
      )}

      {masterSearchStatus === 'not_found' && (
          <p className="text-center text-[10px] text-rose-500 font-bold uppercase tracking-widest mt-2 animate-pulse">
              {t('db_master_not_found')}
          </p>
      )}
    </div>
  );
});

export default PartNumberInput;

import React, { useState, useEffect, useRef, useMemo, memo } from 'react';
import { useLanguage } from './LanguageContext';
import { db } from '../firebase';
import { doc, getDoc } from 'firebase/firestore';

interface PartNumberInputProps {
  parts: string[];
  onPartSelect: (part: string | null) => void;
  onInputChange?: (value: string) => void;
  placeholder?: string;
  value: string | null;
  onRequestPart?: (part: string) => Promise<boolean>;
  inputRef?: React.RefObject<HTMLInputElement>;
  onKeyDown?: React.KeyboardEventHandler<HTMLInputElement>;
}

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
    </svg>
);

const PlusIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
  </svg>
);

const GlobeIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9" />
    </svg>
);

const PartNumberInput: React.FC<PartNumberInputProps> = memo(({ parts, onPartSelect, onInputChange, placeholder, value, onRequestPart, inputRef, onKeyDown }) => {
  const [query, setQuery] = useState<string>('');
  const [isDropdownVisible, setIsDropdownVisible] = useState<boolean>(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const { t } = useLanguage();

  const [reportStatus, setReportStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [masterSearchStatus, setMasterSearchStatus] = useState<'idle' | 'loading' | 'found' | 'not_found'>('idle');

  useEffect(() => {
    setQuery(value || '');
  }, [value]);

  const filteredParts = useMemo(() => {
    const trimmedQuery = query.trim();
    if (trimmedQuery === '') return parts.slice(0, 50);

    const q = trimmedQuery.toLowerCase();
    // Wildcard search support
    if (q.includes('*')) {
      const regexStr = q.replace(/\*/g, '.*');
      const regex = new RegExp(`^${regexStr}`, 'i');
      return parts.filter(p => regex.test(p)).slice(0, 50);
    }

    return parts.filter(p => p.toLowerCase().includes(q)).slice(0, 50);
  }, [query, parts]);

  useEffect(() => {
    setReportStatus('idle');
    setMasterSearchStatus('idle');
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsDropdownVisible(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSelectPart = (part: string) => {
    setQuery(part);
    onPartSelect(part);
    if (onInputChange) onInputChange(part);
    setIsDropdownVisible(false);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = e.target.value;
    setQuery(newValue);
    if (onInputChange) onInputChange(newValue);

    const exactMatch = parts.find(p => p.toLowerCase() === newValue.trim().toLowerCase());
    if (exactMatch) {
      onPartSelect(exactMatch);
    } else {
      onPartSelect(null);
    }
  };

  const handleInternalKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      setIsDropdownVisible(false);
    }
    if (onKeyDown) onKeyDown(e);
  };

  const handleRequestClick = async (e: React.MouseEvent) => {
    e.preventDefault();
    if (onRequestPart && query.trim()) {
        setReportStatus('loading');
        const success = await onRequestPart(query.trim());
        if (success) {
            setReportStatus('success');
            setIsDropdownVisible(false);
            setTimeout(() => setReportStatus('idle'), 3000);
        } else {
            setReportStatus('idle');
        }
    }
  };

  // --- NOVINKA: Master DB Lookup ---
  const handleMasterLookup = async (e: React.MouseEvent) => {
      e.preventDefault();
      const partToFind = query.trim().toUpperCase();
      if (!partToFind) return;

      setMasterSearchStatus('loading');
      try {
          // Načítame master katalóg
          const masterRef = doc(db, 'settings', 'master_catalog');
          const snap = await getDoc(masterRef);

          if (snap.exists()) {
              const data = snap.data();
              const allMasterParts = (data.parts || []) as {p: string, d: string}[];
              const found = allMasterParts.find(m => m.p.toUpperCase() === partToFind);

              if (found) {
                  setMasterSearchStatus('found');
                  if (window.confirm(t('db_master_found'))) {
                      // Automatický import cez callback (cez PartSearchScreen -> onAddPart)
                      // Pre zjednodušenie tu len nastavíme hodnotu
                      handleSelectPart(found.p);
                  }
              } else {
                  setMasterSearchStatus('not_found');
              }
          } else {
              setMasterSearchStatus('not_found');
          }
      } catch (err) {
          console.error("Master lookup failed", err);
          setMasterSearchStatus('not_found');
      }
  };

  const isExactMatch = useMemo(() => parts.some(p => p.toLowerCase() === query.trim().toLowerCase()), [query, parts]);
  const hasWildcard = query.includes('*');

  // Booleans for state to avoid TS2367 errors due to narrowing in JSX
  const masterIsIdle = masterSearchStatus === 'idle';
  const masterIsLoading = masterSearchStatus === 'loading';
  const masterIsNotFound = masterSearchStatus === 'not_found';

  const reportIsIdle = reportStatus === 'idle';
  const reportIsLoading = reportStatus === 'loading';
  const reportIsSuccess = reportStatus === 'success';

  const showMasterLookup = query.trim() !== '' && !isExactMatch && !hasWildcard && (masterIsIdle || masterIsLoading);
  const showReportButton = onRequestPart && query.trim() !== '' && !isExactMatch && !hasWildcard && (masterIsNotFound || !reportIsIdle);

  return (
    <div className="relative" ref={containerRef}>
      <div className="relative">
        <span className="absolute inset-y-0 left-0 flex items-center pl-4">
          <SearchIcon className="h-5 w-5 text-gray-500" />
        </span>
        <input
          type="text"
          ref={inputRef}
          value={query}
          onChange={handleChange}
          onKeyDown={handleInternalKeyDown}
          onFocus={() => setIsDropdownVisible(true)}
          placeholder={placeholder || t('input_wildcard_hint')}
          className="w-full h-12 pl-12 pr-4 bg-gray-700 border border-gray-600 rounded-lg text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-base"
        />
      </div>

      {isDropdownVisible && filteredParts.length > 0 && (
        <div className="absolute z-[999] w-full mt-2 bg-gray-800 border border-gray-700 rounded-lg shadow-2xl max-h-60 overflow-y-auto">
          <ul className="divide-y divide-gray-700">
            {filteredParts.map((part, index) => (
              <li
                key={index}
                onClick={() => handleSelectPart(part)}
                className="px-4 py-3 text-gray-300 hover:bg-teal-600 hover:text-white cursor-pointer transition-colors duration-150 font-mono text-base font-bold"
              >
                {part}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Tlačidlo pre Master DB Lookup */}
      {showMasterLookup && (
          <div className="mt-2 animate-fade-in">
              <button
                type="button"
                onMouseDown={handleMasterLookup}
                disabled={masterIsLoading}
                className="w-full py-3 px-4 bg-indigo-600/20 border border-indigo-500/50 hover:bg-indigo-600/40 text-indigo-400 font-bold rounded-lg flex items-center justify-center gap-2 transition-all active:scale-95"
              >
                  {masterIsLoading ? (
                      <div className="w-4 h-4 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin"></div>
                  ) : <GlobeIcon className="w-4 h-4" />}
                  <span className="text-xs uppercase tracking-widest">{t('db_master_lookup')}</span>
              </button>
          </div>
      )}

      {showReportButton && (
        <div className="mt-2 animate-fade-in">
             <button
                type="button"
                onMouseDown={handleRequestClick}
                disabled={!reportIsIdle}
                className={`w-full py-4 px-4 font-bold rounded-lg shadow-md flex items-center justify-center gap-2 transition-all duration-200 hover:scale-[1.01] ${
                    reportIsSuccess 
                    ? 'bg-green-600 border border-green-500 text-white cursor-default' 
                    : reportIsLoading
                    ? 'bg-yellow-800 border border-yellow-700 text-yellow-200 cursor-wait'
                    : 'bg-yellow-700 hover:bg-yellow-600 border border-yellow-500 text-white'
                }`}
            >
                {reportIsLoading ? (
                     <span className="text-base">{t('report_btn_loading')}</span>
                ) : reportIsSuccess ? (
                     <span className="text-base">{t('report_btn_success')}</span>
                ) : (
                    <>
                        <PlusIcon className="w-6 h-6 text-yellow-200" />
                        <span className="text-base">{t('report_btn_idle')} <strong>{query}</strong></span>
                    </>
                )}
            </button>
            <p className="text-center text-sm text-gray-500 mt-2">
                {reportIsSuccess ? t('report_hint_success') : t('report_hint_idle')}
            </p>
        </div>
      )}

      {masterSearchStatus === 'not_found' && reportIsIdle && (
          <p className="text-center text-[10px] text-rose-500 font-bold uppercase tracking-widest mt-2 animate-pulse">
              {t('db_master_not_found')}
          </p>
      )}
    </div>
  );
});

export default PartNumberInput;

import React from 'react';
import { Task, PriorityLevel, DBItem } from '../../../types/appTypes';
import { useLanguage } from '../../LanguageContext';
import TaskBadges from './TaskBadges';
import TaskActions from './TaskActions';

interface TaskCardProps {
  task: Task;
  currentUserName: string;
  isSystemInventoryTask: boolean;
  copiedId: string | null;
  hasPermission: (perm: string) => boolean;
  onSetInProgress: (id: string) => void;
  onToggleTask: (id: string) => void;
  onToggleBlock: (id: string) => void;
  onToggleManualBlock: (id: string) => void;
  onExhaustSearch: (id: string) => void;
  onMarkAsIncorrect: (id: string) => void;
  handleMissingClick: (task: Task, e: React.MouseEvent) => void;
  handleNoteClick: (task: Task) => void;
  handleDeleteClick: (id: string) => void;
  handleDeleteNoteClick?: (id: string) => void;
  handleCopyPart: (id: string, text: string) => void;
  openPriorityModal: (task: Task) => void;
  onAuditPart?: (task: Task) => void;
  resolveName: (username?: string | null) => string;
}

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg>
);

const UserIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
    </svg>
);

const TaskCard: React.FC<TaskCardProps> = (props) => {
  const { t, language } = useLanguage();
  const { task, resolveName } = props;

  const isSearchingMode = !!task.isBlocked;
  const isManualBlocked = !!task.isManualBlocked;
  const isAuditInProgress = !!task.isAuditInProgress;
  const isUrgent = task.priority === 'URGENT' && !task.isDone;
  const isNoteLockedByAudit = !!(task.auditFinalBadge && !props.hasPermission('perm_btn_audit'));

  // --- SMART TIME LOGIC ---
  const formatTime = (ts?: number) => {
    if (!ts) return '';
    const now = Date.now();
    const diff = now - ts;

    if (diff < 60000) return language === 'sk' ? 'Práve teraz' : 'Just now';

    const date = new Date(ts);
    const today = new Date();
    const isToday = date.toDateString() === today.toDateString();

    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);
    const isYesterday = date.toDateString() === yesterday.toDateString();

    const timeStr = date.toLocaleTimeString(language === 'sk' ? 'sk-SK' : 'en-US', { hour: '2-digit', minute: '2-digit' });

    if (isToday) return (language === 'sk' ? 'Dnes, ' : 'Today, ') + timeStr;
    if (isYesterday) return (language === 'sk' ? 'Včera, ' : 'Yesterday, ') + timeStr;

    return date.toLocaleDateString(language === 'sk' ? 'sk-SK' : 'en-US', { day: '2-digit', month: '2-digit' }) + ', ' + timeStr;
  };

  let bgClass = "";
  let borderClass = "";
  let textClass = "text-white";

  if (task.isDone) {
    bgClass = "bg-gray-800 opacity-60";
    textClass = "text-gray-500 line-through";
  } else {
    if (isManualBlocked) { bgClass = "bg-black"; textClass = "text-gray-500"; borderClass = "border-l-4 border-gray-800"; }
    else if (isAuditInProgress) { bgClass = "bg-amber-500/20"; borderClass = "border-l-4 border-amber-500"; }
    else if (isSearchingMode) { bgClass = "bg-gray-800"; borderClass = "border-l-4 border-gray-600 shadow-inner"; }
    else if (props.isSystemInventoryTask) { bgClass = "bg-[#4169E1]/20"; borderClass = "border-l-4 border-[#4169E1]"; }
    else if (task.isInProgress) { bgClass = "bg-[#FFD700]/20"; borderClass = "border-l-4 border-[#FFD700]"; }
    else if (task.isMissing) { bgClass = "bg-red-900/20"; borderClass = "border-l-4 border-red-500"; }
    else if (task.isLogistics) { bgClass = "bg-sky-900/10"; borderClass = "border-l-4 border-sky-500"; }
    else {
      switch (task.priority) {
        case 'URGENT': bgClass = "bg-[#FF8C00]/20"; borderClass = "border-l-4 border-[#FF8C00]"; break;
        case 'LOW': bgClass = "bg-[#1E90FF]/20"; borderClass = "border-l-4 border-[#1E90FF]"; break;
        case 'NORMAL':
        default: bgClass = "bg-[#8A2BE2]/20"; borderClass = "border-l-4 border-[#8A2BE2]"; break;
      }
    }
  }

  const renderFormattedText = (text: string | undefined, isLarge: boolean = true) => {
    if (!text) return null;
    if (!text.includes(';')) return text;
    const parts = text.split(';');
    return parts.map((part, index) => (
      <React.Fragment key={index}>
        {part.trim()}
        {index < parts.length - 1 && (
          <span className={`mx-2 text-teal-500/40 font-light inline-block transform ${isLarge ? 'scale-110 translate-y-[-1px]' : 'scale-90'}`}>→</span>
        )}
      </React.Fragment>
    ));
  };

  const getUnitLabel = (count: number, unit: string, isInventory: boolean) => {
    if (isInventory) return "pol.";
    let key = count === 1 ? `unit_${unit}_1` : (language === 'sk' && count >= 2 && count <= 4 ? `unit_${unit}_2_4` : `unit_${unit}_5`);
    return t(key as any) || unit;
  };

  const qtyNum = parseFloat(task.quantity || '0');
  const unitLabel = getUnitLabel(qtyNum, task.quantityUnit || '', props.isSystemInventoryTask);

  return (
    <div className={`group relative flex flex-col sm:flex-row rounded-lg shadow-md overflow-hidden transition-all duration-200 items-stretch ${bgClass} ${borderClass} ${!task.isDone ? 'hover:shadow-lg' : ''}`}>
      {isUrgent && !isManualBlocked && <div className="absolute left-0 top-0 bottom-0 w-1 bg-[#FF8C00] animate-pulse z-50"></div>}

      {isSearchingMode && !task.isDone && (
        <div className="absolute right-20 top-1/2 -translate-y-1/2 pointer-events-none opacity-10">
          <SearchIcon className="w-32 h-32 text-gray-400" />
        </div>
      )}

      <div className="flex-grow p-4 flex flex-col gap-1 min-w-0 relative">
        <div className="relative z-10">

          <div className="mb-2">
             <div className="flex flex-wrap gap-2">
                {task.auditFinalBadge && (
                    <span className="bg-amber-600 text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded border border-amber-500 shadow-sm inline-block">
                        📌 {task.auditFinalBadge}
                    </span>
                )}
                <TaskBadges 
                    task={task} 
                    isSystemInventoryTask={props.isSystemInventoryTask} 
                    isAuditInProgress={isAuditInProgress} 
                    isSearchingMode={isSearchingMode} 
                    isManualBlocked={isManualBlocked} 
                    isUrgent={isUrgent} 
                    resolveName={resolveName}
                />
             </div>
          </div>

          <div className="flex justify-between items-start gap-3 mt-1">
            <div className="flex flex-col min-w-0">
                <h3 
                className={`text-2xl sm:text-3xl font-bold break-words whitespace-normal leading-tight cursor-copy active:scale-[0.98] transition-transform ${textClass}`}
                onClick={() => props.handleCopyPart(task.id, task.partNumber || '')}
                title={language === 'sk' ? "Kliknite pre kopírovanie" : "Click to copy"}
                >
                {renderFormattedText(task.partNumber || task.text)}
                {props.copiedId === task.id && (
                    <span className="ml-2 text-xs bg-green-600 text-white px-1.5 py-0.5 rounded-full animate-bounce inline-block font-sans lowercase align-middle">
                    {t('copied_msg')}
                    </span>
                )}
                </h3>
            </div>
            <div className="flex flex-col items-end flex-shrink-0">
              <span className={`bg-black border border-gray-700 shadow-inner px-3 py-1 rounded-full text-xl font-bold ${textClass}`}>{task.quantity || "0"} <span className="ml-1 text-lg font-normal">{unitLabel}</span></span>
            </div>
          </div>

          <div className="flex flex-wrap gap-2 items-center mt-1">
            <span className={`text-lg font-bold uppercase tracking-wider ${task.isDone ? 'text-gray-600' : isManualBlocked ? 'text-gray-600' : props.isSystemInventoryTask ? 'text-[#4169E1]' : isAuditInProgress ? 'text-amber-500' : 'text-cyan-400'}`}>{task.workplace || "---"}</span>
            {task.note && <span className="inline-block px-2 py-0.5 rounded bg-[#fef9c3] text-gray-800 text-xs font-bold shadow-sm border border-yellow-200 leading-tight">{task.note}</span>}
          </div>

          {/* NOVÁ SEKICA: INFO O POUŽÍVATEĽOCH A ČASE */}
          <div className="flex flex-wrap items-center gap-x-4 gap-y-1 mt-3 pt-3 border-t border-white/5 opacity-80">
              <div className="flex items-center gap-1.5">
                  <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">{language === 'sk' ? 'ZADAL:' : 'CREATED:'}</span>
                  <span className="text-[10px] font-bold text-teal-400 uppercase">{resolveName(task.createdBy)}</span>
                  <span className="text-[10px] font-mono text-slate-500">{formatTime(task.createdAt)}</span>
              </div>

              {task.isDone && (
                  <div className="flex items-center gap-1.5 sm:border-l sm:border-slate-700 sm:pl-4">
                      <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">{language === 'sk' ? 'VYBAVIL:' : 'DONE BY:'}</span>
                      <span className="text-[10px] font-bold text-green-500 uppercase">{resolveName(task.completedBy)}</span>
                      <span className="text-[10px] font-mono text-slate-500">{formatTime(task.completedAt)}</span>
                  </div>
              )}
          </div>

        </div>
      </div>

      <div className="flex flex-shrink-0 items-center justify-center p-3 z-10">
        <TaskActions 
          task={task} 
          isSystemInventoryTask={props.isSystemInventoryTask} 
          isSearchingMode={isSearchingMode} 
          isManualBlocked={isManualBlocked} 
          isAuditInProgress={isAuditInProgress} 
          isNoteLockedByAudit={isNoteLockedByAudit} 
          copiedId={props.copiedId} 
          hasPermission={props.hasPermission} 
          onSetInProgress={props.onSetInProgress} 
          onToggleTask={props.onToggleTask} 
          onToggleBlock={props.onToggleBlock} 
          onToggleManualBlock={props.onToggleManualBlock} 
          onExhaustSearch={props.onExhaustSearch}
          onMarkAsIncorrect={props.onMarkAsIncorrect} 
          handleMissingClick={props.handleMissingClick} 
          handleNoteClick={props.handleNoteClick} 
          handleDeleteClick={props.handleDeleteClick} 
          handleCopyPart={props.handleCopyPart} 
          openPriorityModal={props.openPriorityModal} 
          onAuditPart={props.onAuditPart} 
        />
      </div>
    </div>
  );
};

