  }, [props.workplaces, wpSearch]);

  const sortedSectors = useMemo(() => {
    return [...props.mapSectors].sort((a, b) => (a.order || 0) - (b.order || 0) || (a.name || '').localeCompare(b.name || ''));
  }, [props.mapSectors]);

  // --- HANDLERS ---

  // Obstacle
