import React, { useState, useMemo } from 'react';
import { Task, UserData, MapSector, DBItem, SystemConfig, MapObstacle } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { COLOR_MAP } from '../../constants/uiConstants';

interface MapVisualizationTabProps {
  tasks: Task[];
  draftTasks: Task[];
  fetchSanons: () => Promise<any[]>;
  users: UserData[];
  mapSectors: MapSector[];
  workplaces: DBItem[];
  logisticsOperations: DBItem[];
  mapObstacles: MapObstacle[];
  systemConfig: SystemConfig;
  resolveName: (username?: string | null) => string;
}

interface Point { x: number; y: number; label: string; type: 'wp' | 'sector' | 'log'; id: string; color?: string }
interface RouteSegment { path: {x: number, y: number}[]; worker: string; isTransit: boolean; taskType: 'prod' | 'log' }

const GRID_SIZE = 20; // Rozlíšenie mriežky v pixeloch (cca 2 metre)

const MapVisualizationTab: React.FC<MapVisualizationTabProps> = ({
  tasks, draftTasks, fetchSanons, users, mapSectors, workplaces, logisticsOperations, mapObstacles = [], systemConfig, resolveName
}) => {
  const { t, language } = useLanguage();

  const [dateFrom, setDateFrom] = useState(new Date().toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);
  const [selectedWorkers, setSelectedWorkers] = useState<string[]>([]);
  const [allData, setAllData] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleLoadMap = async () => {
    setIsLoading(true);
    try {
        const sanons = await fetchSanons();
        const combined: Task[] = [...tasks, ...draftTasks];
        sanons.forEach(s => { if (s.tasks) combined.push(...s.tasks); });

        const startTs = new Date(dateFrom).setHours(0,0,0,0);
        const endTs = new Date(dateTo).setHours(23,59,59,999);

        const filtered = combined.filter(t => {
            const ts = t.completedAt || t.createdAt || 0;
            return ts >= startTs && ts <= endTs && t.isDone;
        });

        const uniqueMap = new Map();
        filtered.forEach(t => uniqueMap.set(t.id, t));
        setAllData(Array.from(uniqueMap.values()));
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  // --- PATHFINDING ENGINE (BFS) ---
  const { segments, nodes, obstacles, viewBox } = useMemo(() => {
    const pointsMap = new Map<string, Point>();
    workplaces.forEach(w => pointsMap.set(`wp_${w.value}`, { x: w.coordX || 0, y: w.coordY || 0, label: w.value, type: 'wp', id: w.id }));
    logisticsOperations.forEach(l => pointsMap.set(`log_${l.value}`, { x: l.coordX || 0, y: l.coordY || 0, label: l.value, type: 'log', id: l.id }));
    mapSectors.forEach(s => pointsMap.set(`sector_${s.id}`, { x: s.coordX || 0, y: s.coordY || 0, label: s.name, type: 'sector', id: s.id, color: s.color }));

    const allNodes = Array.from(pointsMap.values());
    if (allNodes.length === 0 && mapObstacles.length === 0) {
        return { segments: [], nodes: [], obstacles: [], viewBox: "0 0 1000 1000" };
    }

    const nodeXs = allNodes.length > 0 ? allNodes.map(p => p.x) : [0, 1000];
    const nodeYs = allNodes.length > 0 ? allNodes.map(p => p.y) : [0, 1000];
    const obsXs = mapObstacles.length > 0 ? mapObstacles.flatMap(o => [o.x, o.x + o.w]) : [];
    const obsYs = mapObstacles.length > 0 ? mapObstacles.flatMap(o => [o.y, o.y + o.h]) : [];

    const minX = Math.min(...nodeXs, ...obsXs) - 200;
    const minY = Math.min(...nodeYs, ...obsYs) - 200;
    const maxX = Math.max(...nodeXs, ...obsXs) + 200;
    const maxY = Math.max(...nodeYs, ...obsYs) + 200;

    // Pomocná funkcia: Je bod v prekážke?
    const isPointBlocked = (px: number, py: number) => {
        return mapObstacles.some(o => px >= o.x && px <= o.x + o.w && py >= o.y && py <= o.y + o.h);
    };

    // BFS Pathfinding mriežka
    const findShortestPath = (start: {x: number, y: number}, end: {x: number, y: number}) => {
        // Ak sú štart a cieľ rovnaké
        if (Math.abs(start.x - end.x) < 5 && Math.abs(start.y - end.y) < 5) return [start];

        // Previesť na súradnice mriežky
        const startG = { x: Math.round(start.x / GRID_SIZE), y: Math.round(start.y / GRID_SIZE) };
        const endG = { x: Math.round(end.x / GRID_SIZE), y: Math.round(end.y / GRID_SIZE) };

        const queue: { x: number, y: number, path: {x: number, y: number}[] }[] = [];
        queue.push({ ...startG, path: [start] });

        const visited = new Set<string>();
        visited.add(`${startG.x},${startG.y}`);

        // Bezpečnostný limit krokov (prevencia nekonečnej slučky/lagu)
        let steps = 0;
        const maxSteps = 1500; 

        while (queue.length > 0 && steps < maxSteps) {
            steps++;
            const current = queue.shift()!;

            // Ak sme v blízkosti cieľa
            if (current.x === endG.x && current.y === endG.y) {
                return [...current.path, end];
            }

            // Susedia (Hore, Dole, Vľavo, Vpravo)
            const neighbors = [
                { x: current.x + 1, y: current.y },
                { x: current.x - 1, y: current.y },
                { x: current.x, y: current.y + 1 },
                { x: current.x, y: current.y - 1 }
            ];

            for (const n of neighbors) {
                const key = `${n.x},${n.y}`;
                if (!visited.has(key)) {
                    visited.add(key);

                    // Skontrolovať kolíziu v reálnych pixeloch
                    const realX = n.x * GRID_SIZE;
                    const realY = n.y * GRID_SIZE;

                    // Ak nie je blokovaný, pridaj do fronty
                    if (!isPointBlocked(realX, realY)) {
                        queue.push({ 
                            ...n, 
                            path: [...current.path, { x: realX, y: realY }] 
                        });
                    }
                }
            }
        }

        // Fallback: Ak BFS zlyhá (napr. cieľ je v stene), vráť priamu čiaru
        return [start, end];
    };

    const workerSegments: RouteSegment[] = [];
    const filteredByWorker = selectedWorkers.length > 0 
        ? allData.filter(t => selectedWorkers.includes(t.completedBy || '')) 
        : allData;

    const grouped = new Map<string, Task[]>();
    filteredByWorker.forEach(t => {
        const worker = t.completedBy || 'Unknown';
        if (!grouped.has(worker)) grouped.set(worker, []);
        grouped.get(worker)!.push(t);
    });

    grouped.forEach((workerTasks, worker) => {
        const sorted = [...workerTasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));
        let prevEnd: Point | null = null;

        sorted.forEach(task => {
            let startNode: Point | null = null;
            let endNode: Point | null = null;

            if (task.isLogistics) {
                const op = pointsMap.get(`log_${task.workplace}`);
                startNode = pointsMap.get(`sector_${task.sourceSectorId}`) || op || null;
                endNode = pointsMap.get(`sector_${task.targetSectorId}`) || op || null;
            } else {
                startNode = pointsMap.get(`sector_${task.pickedFromSectorId}`) || null;
                endNode = pointsMap.get(`wp_${task.workplace}`) || null;
            }

            if (startNode && endNode) {
                if (prevEnd) {
                    workerSegments.push({ 
                        path: findShortestPath(prevEnd, startNode), 
                        worker, isTransit: true, taskType: task.isLogistics ? 'log' : 'prod' 
                    });
                }
                workerSegments.push({ 
                    path: findShortestPath(startNode, endNode), 
                    worker, isTransit: false, taskType: task.isLogistics ? 'log' : 'prod' 
                });
                prevEnd = endNode;
            }
        });
    });

    return { 
        segments: workerSegments, 
        nodes: allNodes, 
        obstacles: mapObstacles,
        viewBox: `${minX} ${minY} ${maxX - minX} ${maxY - minY}` 
    };
  }, [allData, selectedWorkers, workplaces, logisticsOperations, mapSectors, mapObstacles]);

  const generatePathData = (path: {x: number, y: number}[]) => {
      if (path.length === 0) return "";
      return `M ${path[0].x} ${path[0].y} ` + path.slice(1).map(p => `L ${p.x} ${p.y}`).join(' ');
  };

  const toggleWorker = (id: string) => {
      setSelectedWorkers(prev => prev.includes(id) ? prev.filter(w => w !== id) : [...prev, id]);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in px-2 md:px-0">

        {/* CONTROL PANEL */}
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-5 shadow-xl">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="md:col-span-1 space-y-4">
                    <h3 className="text-sm font-black text-amber-500 uppercase tracking-widest border-b border-amber-900/30 pb-2">Analytické obdobie</h3>
                    <div className="grid grid-cols-2 gap-2">
                        <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-amber-500 transition-colors" />
                        <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-amber-500 transition-colors" />
                    </div>
                    <button onClick={handleLoadMap} disabled={isLoading} className="w-full h-12 bg-amber-600 hover:bg-amber-500 text-white font-black rounded-xl uppercase text-xs tracking-widest shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 border-2 border-amber-500 disabled:opacity-50">
                        {isLoading ? '⏳ ...' : '🔄 ' + t('map_load_btn')}
                    </button>
                </div>

                <div className="md:col-span-2 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">{t('map_filter_workers')}</h3>
                    <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto custom-scrollbar">
                        {(users || []).map(u => (
                            <button key={u.username} onClick={() => toggleWorker(u.username)} className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedWorkers.includes(u.username) ? 'bg-teal-500 border-teal-400 text-white shadow-[0_0_10px_rgba(20,184,166,0.3)]' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}>
                                {u.nickname || u.username}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="md:col-span-1 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">Metrika Mapy</h3>
                    <div className="bg-slate-950 p-3 rounded-xl border border-slate-800">
                        <div className="flex justify-between items-center mb-2">
                            <span className="text-[10px] font-black text-slate-500 uppercase">Mierka:</span>
                            <span className="text-[10px] font-black text-teal-400">10 PX = 1 M</span>
                        </div>
                        <div className="flex items-center gap-2">
                             <div className="h-1 w-[50px] bg-slate-700 rounded-full relative">
                                <div className="absolute inset-y-0 left-0 w-px bg-slate-500"></div>
                                <div className="absolute inset-y-0 right-0 w-px bg-slate-500"></div>
                             </div>
                             <span className="text-[9px] font-mono text-slate-500">5 metrov</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* MAP VISUALIZATION AREA */}
        <div className="bg-slate-900 border-2 border-slate-800 rounded-3xl shadow-2xl overflow-hidden relative min-h-[650px] flex flex-col group">
            {isLoading && (
                <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-50 flex flex-col items-center justify-center gap-4">
                    <div className="w-16 h-16 border-4 border-amber-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-amber-500 font-black animate-pulse uppercase tracking-[0.4em] text-lg">{t('map_loading')}</p>
                </div>
            )}

            <div className="flex-grow relative overflow-hidden bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-800/20 via-slate-900 to-slate-950">
                <svg viewBox={viewBox} className="w-full h-full min-h-[650px]" xmlns="http://www.w3.org/2000/svg">
                    <defs>
                        <pattern id="grid5m" width="50" height="50" patternUnits="userSpaceOnUse"><path d="M 50 0 L 0 0 0 50" fill="none" stroke="white" strokeWidth="1" strokeOpacity="0.05" /></pattern>
                        <pattern id="grid1m" width="10" height="10" patternUnits="userSpaceOnUse"><path d="M 10 0 L 0 0 0 10" fill="none" stroke="white" strokeWidth="0.5" strokeOpacity="0.02" /></pattern>
                        <pattern id="hatch" patternUnits="userSpaceOnUse" width="10" height="10"><path d="M-1,1 l2,-2 M0,10 l10,-10 M9,11 l2,-2" stroke="white" strokeWidth="1" strokeOpacity="0.1" /></pattern>
                        <filter id="glow-teal"><feGaussianBlur stdDeviation="2.5" result="coloredBlur"/><feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
                        <filter id="glow-sky"><feGaussianBlur stdDeviation="2.5" result="coloredBlur"/><feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
                    </defs>

                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid1m)" />
                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid5m)" />

                    {/* OBSTACLES (Layer 0) */}
                    {obstacles.map((o, idx) => (
                        <g key={o.id || idx}>
                            <rect x={o.x} y={o.y} width={o.w} height={o.h} fill="#1e293b" stroke="#334155" strokeWidth="2" rx="4" />
                            <rect x={o.x} y={o.y} width={o.w} height={o.h} fill="url(#hatch)" rx="4" />
                        </g>
                    ))}

                    {/* ROUTES - Transit (Layer 1) */}
                    {segments.filter(s => s.isTransit).map((s, i) => (
                        <path key={`transit-${i}`} d={generatePathData(s.path)} fill="none" stroke="#475569" strokeWidth="1.2" strokeDasharray="5 5" strokeOpacity="0.5" />
                    ))}

                    {/* ROUTES - Work (Layer 2) */}
                    {segments.filter(s => !s.isTransit).map((s, i) => (
                        <path key={`ride-${i}`} d={generatePathData(s.path)} fill="none" stroke={s.taskType === 'prod' ? '#14b8a6' : '#0ea5e9'} strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" strokeOpacity="0.8" filter={s.taskType === 'prod' ? 'url(#glow-teal)' : 'url(#glow-sky)'} className="hover:stroke-white hover:strokeOpacity-100 transition-all" />
                    ))}

                    {/* NODES - Workplaces & Sectors (Layer 3) */}
                    {nodes.map(node => {
                        const isSector = node.type === 'sector';
                        const colorValue = isSector ? (COLOR_MAP[node.color as keyof typeof COLOR_MAP]?.replace('bg-', '') || 'pink-500') : 'blue-500';
                        return (
                            <g key={node.id} transform={`translate(${node.x}, ${node.y})`} className="group/node">
                                {isSector ? (
                                    <rect x="-12" y="-12" width="24" height="24" rx="6" fill="currentColor" className={`text-${colorValue} opacity-20 border-2 border-current group-hover/node:opacity-40 transition-opacity`} />
                                ) : (
                                    <circle r="9" fill="#0f172a" stroke={node.type === 'wp' ? '#3b82f6' : '#0ea5e9'} strokeWidth="2.5" className="group-hover/node:stroke-white transition-colors" />
                                )}
                                <text y={isSector ? -28 : -22} textAnchor="middle" fill="white" className="text-[9px] font-black uppercase tracking-widest opacity-0 group-hover/node:opacity-100 transition-opacity pointer-events-none drop-shadow-md">{node.label}</text>
                            </g>
                        );
                    })}
                </svg>

                <div className="absolute bottom-6 right-6 bg-slate-900/60 backdrop-blur-md border border-slate-700 p-3 rounded-xl pointer-events-none shadow-2xl">
                     <div className="flex flex-col items-center gap-2">
                        <div className="flex items-center gap-0 w-[100px] h-3 border-x border-slate-400 relative">
                            <div className="absolute top-1/2 left-0 right-0 h-px bg-slate-400 -translate-y-1/2"></div>
                        </div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">10 METROV</span>
                     </div>
                </div>
            </div>
        </div>
    </div>
  );
};

export default MapVisualizationTab;

import React, { useState, useMemo } from 'react';
import { Task, UserData, MapSector, DBItem, SystemConfig, MapObstacle } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { COLOR_MAP } from '../../constants/uiConstants';

interface MapVisualizationTabProps {
  tasks: Task[];
  draftTasks: Task[];
  fetchSanons: () => Promise<any[]>;
  users: UserData[];
  mapSectors: MapSector[];
  workplaces: DBItem[];
  logisticsOperations: DBItem[];
  mapObstacles: MapObstacle[];
  systemConfig: SystemConfig;
  resolveName: (username?: string | null) => string;
}

interface Point { x: number; y: number; label: string; type: 'wp' | 'sector' | 'log'; id: string; color?: string }
interface RouteSegment { path: {x: number, y: number}[]; worker: string; isTransit: boolean; taskType: 'prod' | 'log' }

const GRID_SIZE = 20; // 1 mriežka = 20px (cca 2 metre v realite)

const MapVisualizationTab: React.FC<MapVisualizationTabProps> = ({
  tasks, draftTasks, fetchSanons, users, mapSectors, workplaces, logisticsOperations, mapObstacles = [], systemConfig, resolveName
}) => {
  const { t, language } = useLanguage();

  const [dateFrom, setDateFrom] = useState(new Date().toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);
  const [selectedWorkers, setSelectedWorkers] = useState<string[]>([]);
  const [allData, setAllData] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleLoadMap = async () => {
    setIsLoading(true);
    try {
        const sanons = await fetchSanons();
        const combined: Task[] = [...tasks, ...draftTasks];
        sanons.forEach(s => { if (s.tasks) combined.push(...s.tasks); });

        const startTs = new Date(dateFrom).setHours(0,0,0,0);
        const endTs = new Date(dateTo).setHours(23,59,59,999);

        const filtered = combined.filter(t => {
            const ts = t.completedAt || t.createdAt || 0;
            return ts >= startTs && ts <= endTs && t.isDone;
        });

        const uniqueMap = new Map();
        filtered.forEach(t => uniqueMap.set(t.id, t));
        setAllData(Array.from(uniqueMap.values()));
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  // --- PATHFINDING ENGINE (A* MANHATTAN) ---
  const { segments, nodes, obstacles, viewBox } = useMemo(() => {
    const pointsMap = new Map<string, Point>();
    workplaces.forEach(w => pointsMap.set(`wp_${w.value}`, { x: w.coordX || 0, y: w.coordY || 0, label: w.value, type: 'wp', id: w.id }));
    logisticsOperations.forEach(l => pointsMap.set(`log_${l.value}`, { x: l.coordX || 0, y: l.coordY || 0, label: l.value, type: 'log', id: l.id }));
    mapSectors.forEach(s => pointsMap.set(`sector_${s.id}`, { x: s.coordX || 0, y: s.coordY || 0, label: s.name, type: 'sector', id: s.id, color: s.color }));

    const allNodes = Array.from(pointsMap.values());
    if (allNodes.length === 0 && mapObstacles.length === 0) {
        return { segments: [], nodes: [], obstacles: [], viewBox: "0 0 1000 1000" };
    }

    const nodeXs = allNodes.length > 0 ? allNodes.map(p => p.x) : [0, 1000];
    const nodeYs = allNodes.length > 0 ? allNodes.map(p => p.y) : [0, 1000];
    const obsXs = mapObstacles.length > 0 ? mapObstacles.flatMap(o => [o.x, o.x + o.w]) : [];
    const obsYs = mapObstacles.length > 0 ? mapObstacles.flatMap(o => [o.y, o.y + o.h]) : [];

    const minX = Math.min(...nodeXs, ...obsXs) - 100;
    const minY = Math.min(...nodeYs, ...obsYs) - 100;
    const maxX = Math.max(...nodeXs, ...obsXs) + 100;
    const maxY = Math.max(...nodeYs, ...obsYs) + 100;

    const isBlocked = (px: number, py: number) => {
        return (mapObstacles || []).some(o => px >= o.x && px < o.x + o.w && py >= o.y && py < o.y + o.h);
    };

    const findAStarPath = (start: {x: number, y: number}, end: {x: number, y: number}) => {
        const startG = { x: Math.round(start.x / GRID_SIZE), y: Math.round(start.y / GRID_SIZE) };
        const endG = { x: Math.round(end.x / GRID_SIZE), y: Math.round(end.y / GRID_SIZE) };

        if (startG.x === endG.x && startG.y === endG.y) return [start, end];

        const openSet = [{ ...startG, g: 0, f: Math.abs(startG.x - endG.x) + Math.abs(startG.y - endG.y), path: [start] }];
        const closedSet = new Set<string>();

        let steps = 0;
        const maxSteps = 2000;

        while (openSet.length > 0 && steps < maxSteps) {
            steps++;
            openSet.sort((a, b) => a.f - b.f);
            const current = openSet.shift()!;

            if (current.x === endG.x && current.y === endG.y) {
                return [...current.path, end];
            }

            closedSet.add(`${current.x},${current.y}`);

            const neighbors = [
                { x: current.x + 1, y: current.y },
                { x: current.x - 1, y: current.y },
                { x: current.x, y: current.y + 1 },
                { x: current.x, y: current.y - 1 }
            ];

            for (const n of neighbors) {
                if (closedSet.has(`${n.x},${n.y}`)) continue;

                const realX = n.x * GRID_SIZE;
                const realY = n.y * GRID_SIZE;

                // Kontrola prekážky
                if (isBlocked(realX, realY)) continue;

                const g = current.g + 1;
                const h = Math.abs(n.x - endG.x) + Math.abs(n.y - endG.y);
                const f = g + h;

                const existing = openSet.find(o => o.x === n.x && o.y === n.y);
                if (existing && existing.g <= g) continue;

                if (!existing) {
                    openSet.push({ ...n, g, f, path: [...current.path, { x: realX, y: realY }] });
                } else {
                    existing.g = g;
                    existing.f = f;
                    existing.path = [...current.path, { x: realX, y: realY }];
                }
            }
        }
        return [start, end]; // Fallback
    };

    const workerSegments: RouteSegment[] = [];
    const filteredByWorker = selectedWorkers.length > 0 
        ? allData.filter(t => selectedWorkers.includes(t.completedBy || '')) 
        : allData;

    const grouped = new Map<string, Task[]>();
    filteredByWorker.forEach(t => {
        const worker = t.completedBy || 'Unknown';
        if (!grouped.has(worker)) grouped.set(worker, []);
        grouped.get(worker)!.push(t);
    });

    grouped.forEach((workerTasks, worker) => {
        const sorted = [...workerTasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));
        let prevEnd: Point | null = null;

        sorted.forEach(task => {
            let startPoint: Point | null = null;
            let endPoint: Point | null = null;

            if (task.isLogistics) {
                const op = pointsMap.get(`log_${task.workplace}`);
                startPoint = pointsMap.get(`sector_${task.sourceSectorId}`) || op || null;
                endPoint = pointsMap.get(`sector_${task.targetSectorId}`) || op || null;
            } else {
                startPoint = pointsMap.get(`sector_${task.pickedFromSectorId}`) || null;
                endPoint = pointsMap.get(`wp_${task.workplace}`) || null;
            }

            if (startPoint && endPoint) {
                if (prevEnd) {
                    workerSegments.push({ path: findAStarPath(prevEnd, startPoint), worker, isTransit: true, taskType: task.isLogistics ? 'log' : 'prod' });
                }
                workerSegments.push({ path: findAStarPath(startPoint, endPoint), worker, isTransit: false, taskType: task.isLogistics ? 'log' : 'prod' });
                prevEnd = endPoint;
            }
        });
    });

    return { 
        segments: workerSegments, 
        nodes: allNodes, 
        obstacles: mapObstacles,
        viewBox: `${minX} ${minY} ${maxX - minX} ${maxY - minY}` 
    };
  }, [allData, selectedWorkers, workplaces, logisticsOperations, mapSectors, mapObstacles]);

  const generatePathData = (path: {x: number, y: number}[]) => {
      if (path.length === 0) return "";
      // Vyhladenie Manhattan trasy (spájanie rovných úsekov)
      const simplified = [path[0]];
      for (let i = 1; i < path.length - 1; i++) {
          const prev = path[i-1];
          const curr = path[i];
          const next = path[i+1];
          // Ak nie je bod na priamke, ponecháme ho (bod zlomu)
          if (!((prev.x === curr.x && curr.x === next.x) || (prev.y === curr.y && curr.y === next.y))) {
              simplified.push(curr);
          }
      }
      if (path.length > 1) simplified.push(path[path.length - 1]);

      return `M ${simplified[0].x} ${simplified[0].y} ` + simplified.slice(1).map(p => `L ${p.x} ${p.y}`).join(' ');
  };

  const toggleWorker = (id: string) => {
      setSelectedWorkers(prev => prev.includes(id) ? prev.filter(w => w !== id) : [...prev, id]);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in px-2 md:px-0">

        {/* CONTROL PANEL */}
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-5 shadow-xl">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="md:col-span-1 space-y-4">
                    <h3 className="text-sm font-black text-amber-500 uppercase tracking-widest border-b border-amber-900/30 pb-2">Analytické obdobie</h3>
                    <div className="grid grid-cols-2 gap-2">
                        <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-amber-500 transition-colors" />
                        <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-amber-500 transition-colors" />
                    </div>
                    <button onClick={handleLoadMap} disabled={isLoading} className="w-full h-12 bg-amber-600 hover:bg-amber-500 text-white font-black rounded-xl uppercase text-xs tracking-widest shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 border-2 border-amber-500 disabled:opacity-50">
                        {isLoading ? '⏳ ...' : '🔄 ' + t('map_load_btn')}
                    </button>
                </div>

                <div className="md:col-span-2 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">{t('map_filter_workers')}</h3>
                    <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto custom-scrollbar">
                        {(users || []).map(u => (
                            <button key={u.username} onClick={() => toggleWorker(u.username)} className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedWorkers.includes(u.username) ? 'bg-teal-500 border-teal-400 text-white shadow-[0_0_10px_rgba(20,184,166,0.3)]' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}>
                                {u.nickname || u.username}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="md:col-span-1 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">Metrika Mapy</h3>
                    <div className="bg-slate-950 p-3 rounded-xl border border-slate-800">
                        <div className="flex justify-between items-center mb-2">
                            <span className="text-[10px] font-black text-slate-500 uppercase">Mierka:</span>
                            <span className="text-[10px] font-black text-teal-400">10 PX = 1 M</span>
                        </div>
                        <div className="flex items-center gap-2">
                             <div className="h-1 w-[50px] bg-slate-700 rounded-full relative">
                                <div className="absolute inset-y-0 left-0 w-px bg-slate-500"></div>
                                <div className="absolute inset-y-0 right-0 w-px bg-slate-500"></div>
                             </div>
                             <span className="text-[9px] font-mono text-slate-500">5 metrov</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* MAP VISUALIZATION AREA */}
        <div className="bg-slate-900 border-2 border-slate-800 rounded-3xl shadow-2xl overflow-hidden relative min-h-[650px] flex flex-col group">
            {isLoading && (
                <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-50 flex flex-col items-center justify-center gap-4">
                    <div className="w-16 h-16 border-4 border-amber-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-amber-500 font-black animate-pulse uppercase tracking-[0.4em] text-lg">{t('map_loading')}</p>
                </div>
            )}

            <div className="flex-grow relative overflow-hidden bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-800/20 via-slate-900 to-slate-950">
                <svg viewBox={viewBox} className="w-full h-full min-h-[650px]" xmlns="http://www.w3.org/2000/svg">
                    <defs>
                        <pattern id="grid5m" width="50" height="50" patternUnits="userSpaceOnUse"><path d="M 50 0 L 0 0 0 50" fill="none" stroke="white" strokeWidth="1" strokeOpacity="0.05" /></pattern>
                        <pattern id="grid1m" width="10" height="10" patternUnits="userSpaceOnUse"><path d="M 10 0 L 0 0 0 10" fill="none" stroke="white" strokeWidth="0.5" strokeOpacity="0.02" /></pattern>
                        <pattern id="hatch" patternUnits="userSpaceOnUse" width="10" height="10"><path d="M-1,1 l2,-2 M0,10 l10,-10 M9,11 l2,-2" stroke="white" strokeWidth="1" strokeOpacity="0.1" /></pattern>
                        <filter id="glow-teal"><feGaussianBlur stdDeviation="3" result="coloredBlur"/><feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
                        <filter id="glow-sky"><feGaussianBlur stdDeviation="3" result="coloredBlur"/><feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
                    </defs>

                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid1m)" />
                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid5m)" />

                    {/* OBSTACLES (Layer 0) */}
                    {obstacles.map((o, idx) => (
                        <g key={o.id || idx}>
                            <rect x={o.x} y={o.y} width={o.w} height={o.h} fill="#1e293b" stroke="#334155" strokeWidth="2" rx="4" />
                            <rect x={o.x} y={o.y} width={o.w} height={o.h} fill="url(#hatch)" rx="4" />
                            {o.w > 40 && (
                                <text x={o.x + o.w/2} y={o.y + o.h/2} textAnchor="middle" dominantBaseline="middle" className="fill-slate-600 text-[10px] font-black uppercase tracking-widest pointer-events-none select-none">{o.name}</text>
                            )}
                        </g>
                    ))}

                    {/* ROUTES - Transit (Layer 1) */}
                    {segments.filter(s => s.isTransit).map((s, i) => (
                        <path key={`transit-${i}`} d={generatePathData(s.path)} fill="none" stroke="#475569" strokeWidth="1.5" strokeDasharray="6 4" strokeOpacity="0.4" />
                    ))}

                    {/* ROUTES - Work (Layer 2) */}
                    {segments.filter(s => !s.isTransit).map((s, i) => (
                        <path key={`ride-${i}`} d={generatePathData(s.path)} fill="none" stroke={s.taskType === 'prod' ? '#14b8a6' : '#0ea5e9'} strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round" strokeOpacity="0.8" filter={s.taskType === 'prod' ? 'url(#glow-teal)' : 'url(#glow-sky)'} className="hover:stroke-white hover:strokeOpacity-100 transition-all duration-300" />
                    ))}

                    {/* NODES - Workplaces & Sectors (Layer 3) */}
                    {nodes.map(node => {
                        const isSector = node.type === 'sector';
                        const colorValue = isSector ? (COLOR_MAP[node.color as keyof typeof COLOR_MAP]?.replace('bg-', '') || 'pink-500') : 'blue-500';
                        return (
                            <g key={node.id} transform={`translate(${node.x}, ${node.y})`} className="group/node">
                                {isSector ? (
                                    <rect x="-14" y="-14" width="28" height="28" rx="8" fill="currentColor" className={`text-${colorValue} opacity-20 border-2 border-current group-hover/node:opacity-50 transition-all cursor-help`} />
                                ) : (
                                    <circle r="10" fill="#0f172a" stroke={node.type === 'wp' ? '#3b82f6' : '#0ea5e9'} strokeWidth="3" className="group-hover/node:stroke-white transition-all cursor-help shadow-lg" />
                                )}
                                <text y={isSector ? -32 : -25} textAnchor="middle" fill="white" className="text-[10px] font-black uppercase tracking-widest opacity-0 group-hover/node:opacity-100 transition-opacity pointer-events-none drop-shadow-md bg-black/50 px-1">{node.label}</text>
                            </g>
                        );
                    })}
                </svg>

                <div className="absolute bottom-6 right-6 bg-slate-900/60 backdrop-blur-md border border-slate-700 p-4 rounded-2xl pointer-events-none shadow-2xl">
                     <div className="flex flex-col items-center gap-2">
                        <div className="flex items-center gap-0 w-[100px] h-3 border-x-2 border-slate-400 relative">
                            <div className="absolute top-1/2 left-0 right-0 h-0.5 bg-slate-400 -translate-y-1/2"></div>
                        </div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">10 METROV</span>
                     </div>
                </div>
            </div>
        </div>
    </div>
  );
};

export default MapVisualizationTab;

import { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  orderBy,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  setDoc,
  getDoc,
  arrayUnion,
  writeBatch,
  getDocs
} from 'firebase/firestore';
import { DBItem, MapSector, PartRequest, BOMRequest, BOMComponent, MapObstacle } from '../../types/appTypes';

export const useMasterData = () => {
  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, BOMComponent[]>>({});
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]);
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [mapObstacles, setMapObstacles] = useState<MapObstacle[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);

  useEffect(() => {
    const unsubWp = onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubLogOps = onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), s => setLogisticsOperations(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubSectors = onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
        const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
        setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0)));
    });
    const unsubPartReq = onSnapshot(collection(db, 'part_requests'), s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest))));
    const unsubBomReq = onSnapshot(collection(db, 'bom_requests'), s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest))));

    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (docSnap) => {
        const cleanMap: Record<string, string> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.value) cleanMap[item.value] = item.description || '';
                });
            }
        }
        setPartsMap(cleanMap);
    });

    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (docSnap) => {
        const cleanMap: Record<string, BOMComponent[]> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.parent && item.child) {
                        if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                        cleanMap[item.parent].push({ child: item.child, consumption: item.consumption || 0 });
                    }
                });
            }
        }
        setBomMap(cleanMap);
    });

    const unsubObstacles = onSnapshot(doc(db, 'settings', 'map_layout'), (docSnap) => {
        if (docSnap.exists()) {
            setMapObstacles(docSnap.data().obstacles || []);
        } else {
            setMapObstacles([]);
        }
    });

    return () => { 
        unsubWp(); unsubLogOps(); unsubSectors(); unsubPartReq(); unsubBomReq();
        unsubParts(); unsubBOM(); unsubObstacles();
    };
  }, []);

  // --- ACTIONS ---

  // Obstacles
  const onAddMapObstacle = async (obs: Omit<MapObstacle, 'id'>) => {
      const id = `obs_${Date.now()}`;
      await setDoc(doc(db, 'settings', 'map_layout'), { 
          obstacles: arrayUnion({ ...obs, id }) 
      }, { merge: true });
  };
  const onDeleteMapObstacle = async (id: string) => {
      const ref = doc(db, 'settings', 'map_layout');
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const filtered = (snap.data().obstacles || []).filter((o: any) => o.id !== id);
          await updateDoc(ref, { obstacles: filtered });
      }
  };

  // Workplaces
  const onAddWorkplace = async (val: string, time: number = 0, x: number = 0, y: number = 0) => {
      await addDoc(collection(db, 'workplaces'), { value: val, standardTime: time, coordX: x, coordY: y });
  };
  const onUpdateWorkplace = async (id: string, updates: Partial<DBItem>) => {
      await updateDoc(doc(db, 'workplaces', id), updates);
  };
  const onDeleteWorkplace = async (id: string) => {
      await deleteDoc(doc(db, 'workplaces', id));
  };
  const onDeleteAllWorkplaces = async () => {
      const snap = await getDocs(collection(db, 'workplaces'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };
  const onBatchAddWorkplaces = async (vals: string[]) => {
      const batch = writeBatch(db);
      vals.forEach(line => {
          if (!line.trim()) return;
          const [val, time] = line.split(';');
          const ref = doc(collection(db, 'workplaces'));
          batch.set(ref, { value: val.trim(), standardTime: parseInt(time) || 0 });
      });
      await batch.commit();
  };

  // Logistics Operations
  const onAddLogisticsOperation = async (val: string, time: number = 0, dist: number = 0, x: number = 0, y: number = 0) => { await addDoc(collection(db, 'logistics_operations'), { value: val, standardTime: time, distancePx: dist, coordX: x, coordY: y }); };
  const onUpdateLogisticsOperation = async (id: string, updates: Partial<DBItem>) => { await updateDoc(doc(logistics_operations, id), updates); };
  const onDeleteLogisticsOperation = async (id: string) => { await deleteDoc(doc(db, 'logistics_operations', id)); };
  const onDeleteAllLogisticsOperations = async () => {
      const snap = await getDocs(collection(db, 'logistics_operations'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };

  // Map Sectors
  const onAddMapSector = async (name: string, x: number, y: number, color?: string) => { await addDoc(collection(db, 'map_sectors'), { name, coordX: x, coordY: y, color }); };
  const onUpdateMapSector = async (id: string, updates: Partial<MapSector>) => { await updateDoc(doc(db, 'map_sectors', id), updates); };
  const onDeleteMapSector = async (id: string) => { await deleteDoc(doc(db, 'map_sectors', id)); };

  // Parts (Single Doc Pattern)
  const onAddPart = async (value: string, description: string = '') => {
      try {
          const newItem = { 
            value: value.toUpperCase(), 
            description 
          };
          await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddParts = async (vals: string[]) => {
    try {
      const itemsToAdd: any[] = [];
      vals.forEach((valLine) => {
        if (!valLine.trim()) return;
        const [p, d] = valLine.split(';');
        if(p) { 
          itemsToAdd.push({ 
            value: p.trim().toUpperCase(), 
            description: d ? d.trim() : '' 
          }); 
        }
      });
      if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
    } catch (error) { console.error("Error batch adding parts:", error); throw error; }
  };
  const onDeletePart = async (val: string) => {
      try {
          const ref = doc(db, 'settings', 'parts');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => i.value !== val);
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error("Error deleting part:", e); }
  };
  const onDeleteAllParts = async () => { try { await setDoc(doc(db, 'settings', 'parts'), { items: [] }); } catch (e) { console.error("Error clearing parts:", e); } };

  // BOM (Single Doc Pattern - Optimized for Quota Guard)
  const onAddBOMItem = async (parent: string, child: string, qty: number) => {
      try {
          const newItem = { 
              parent: parent.toUpperCase(), 
              child: child.toUpperCase(), 
              consumption: qty 
          };
          await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddBOMItems = async (vals: string[]) => {
      try {
          const itemsToAdd: any[] = [];
          vals.forEach(line => {
              if (!line.trim()) return;
              const [p, c, q] = line.split(';');
              if (p && c) { 
                  itemsToAdd.push({ 
                      parent: p.trim().toUpperCase(), 
                      child: c.trim().toUpperCase(), 
                      consumption: parseFloat(q?.replace(',', '.') || '0') 
                  }); 
              }
          });
          if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
      } catch (e) { console.error(e); }
  };
  const onDeleteBOMItem = async (parent: string, child: string) => {
      try {
          const ref = doc(db, 'settings', 'bom');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => !(i.parent === parent && i.child === child));
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error(e); }
  };
  const onDeleteAllBOMItems = async () => { try { await setDoc(doc(db, 'settings', 'bom'), { items: [] }); } catch (e) { console.error(e); } };

  // Requests
  const onRequestPart = async (part: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'part_requests'), { partNumber: part, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeletePartRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'part_requests', id)); } catch(e) { console.error(e); }
  };

  const onRequestBOM = async (parent: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'bom_requests'), { parentPart: parent, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeleteBOMRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'bom_requests', id)); } catch(e) { console.error(e); }
  };

  return {
    partsMap, bomMap, workplaces, logisticsOperations, mapSectors, mapObstacles, partRequests, bomRequests,
    onAddWorkplace, onUpdateWorkplace, onDeleteWorkplace, onDeleteAllWorkplaces, onBatchAddWorkplaces,
    onAddLogisticsOperation, onUpdateLogisticsOperation, onDeleteLogisticsOperation, onDeleteAllLogisticsOperations,
    onAddMapSector, onUpdateMapSector, onDeleteMapSector,
    onAddMapObstacle, onDeleteMapObstacle,
    onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts,
    onAddBOMItem, onBatchAddBOMItems, onDeleteBOMItem, onDeleteAllBOMItems,
    onRequestPart, onDeletePartRequest, 
    onRequestBOM, onDeleteBOMRequest
  };
};

import React, { useState } from 'react';
import { db } from '../../firebase';
import { doc, getDoc, writeBatch } from 'firebase/firestore';
import { useLanguage } from '../LanguageContext';

interface MasterDbSyncModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSyncSuccess: (count: number) => void;
}

const MasterDbSyncModal: React.FC<MasterDbSyncModalProps> = ({ isOpen, onClose, onSyncSuccess }) => {
    const { t, language } = useLanguage();
    const [password, setPassword] = useState('');
    const [status, setStatus] = useState<'idle' | 'connecting' | 'preview' | 'importing'>('idle');
    const [newParts, setNewParts] = useState<{p: string, d: string}[]>([]);

    if (!isOpen) return null;

    const handleConnect = async () => {
        if (!password) return;
        setStatus('connecting');

        try {
            // Simulácia oneskorenia siete pre lepší UX
            await new Promise(r => setTimeout(r, 800));

            // Pripojenie k externému zdroju (chránený master dokument)
            const masterRef = doc(db, 'settings', 'master_catalog');
            const snap = await getDoc(masterRef);

            if (!snap.exists()) {
                // Fallback pre demo účely, ak dokument neexistuje
                console.warn("Master DB document not found. Using demo data if password matches '1234'.");
                if (password === '1234') {
                    setNewParts([
                        { p: 'DEMO-123', d: 'Demo Part 1' },
                        { p: 'DEMO-456', d: 'Demo Part 2' },
                        { p: 'DEMO-789', d: 'Demo Part 3' }
                    ]);
                    setStatus('preview');
                    return;
                }
                alert(t('db_sync_error_fetch'));
                setStatus('idle');
                return;
            }

            const data = snap.data();
            if (data.accessKey !== password) {
                alert(t('db_sync_error_pass'));
                setStatus('idle');
                return;
            }

            // Očakávame štruktúru { parts: [{p: 'číslo', d: 'popis'}, ...] }
            setNewParts(data.parts || []);
            setStatus('preview');
        } catch (e) {
            console.error(e);
            alert(t('db_sync_error_fetch'));
            setStatus('idle');
        }
    };

    const handleImport = async () => {
        setStatus('importing');
        try {
            // Použitie writeBatch podľa pravidla Quota Guard
            const localPartsRef = doc(db, 'settings', 'parts');
            const currentLocal = await getDoc(localPartsRef);

            // Čítame z 'items', nie 'data' (konzistencia s useFirestoreData)
            const currentData = currentLocal.exists() ? (currentLocal.data().items || []) : [];

            // Príprava dát pre lokálny formát - LEN value a description
            const formattedNewParts = newParts.map((np) => ({
                value: np.p.toUpperCase(),
                description: np.d
            }));

            // Merge unikátnych dielov (podľa hodnoty value/p)
            const existingKeys = new Set(currentData.map((x: any) => x.value));
            const uniqueNewParts = formattedNewParts.filter(p => !existingKeys.has(p.value));

            if (uniqueNewParts.length === 0) {
                alert(language === 'sk' ? 'Všetky diely už v databáze existujú.' : 'All parts already exist in database.');
                onClose();
                return;
            }

            const batch = writeBatch(db);
            batch.set(localPartsRef, {
                items: [...currentData, ...uniqueNewParts]
            }, { merge: true });

            await batch.commit();

            // Krátke oneskorenie pre vizuálny efekt dokončenia
            await new Promise(r => setTimeout(r, 500));

            onSyncSuccess(uniqueNewParts.length);
            onClose();
        } catch (e) {
            console.error(e);
            alert("Import failed");
            setStatus('preview');
        }
    };

    return (
        <div className="fixed inset-0 z-[10000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in">
            <div className="bg-slate-900 border-2 border-[#97bc1e]/50 rounded-3xl shadow-[0_0_50px_rgba(151,188,30,0.2)] w-full max-w-lg p-8 relative overflow-hidden flex flex-col max-h-[90vh]">
                {/* Background Decoration */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-[#97bc1e]/5 rounded-full -mr-16 -mt-16 blur-2xl"></div>

                <div className="text-center mb-6 relative z-10 flex-shrink-0">
                    <div className="w-16 h-16 bg-[#97bc1e]/10 rounded-2xl flex items-center justify-center mx-auto mb-4 border border-[#97bc1e]/30">
                        <svg className="w-8 h-8 text-[#97bc1e]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 7v10c0 1.105 3.582 2 8 2s8-.895 8-2V7M4 7c0 1.105 3.582 2 8 2s8-.895 8-2M4 7c0-1.105 3.582-2 8-2s8 .895 8 2m-8 4v10" />
                        </svg>
                    </div>
                    <h3 className="text-2xl font-black text-white uppercase tracking-tighter">{t('db_sync_title')}</h3>
                    <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-2">
                        {status === 'idle' && (language === 'sk' ? 'Zadajte prístupové heslo' : 'Enter access password')}
                        {status === 'connecting' && (language === 'sk' ? 'Pripájam sa k databáze...' : 'Connecting to database...')}
                        {status === 'preview' && (language === 'sk' ? 'Nájdené diely' : 'Found parts')}
                        {status === 'importing' && (language === 'sk' ? 'Ukladám do systému...' : 'Saving to system...')}
                    </p>
                </div>

                <div className="space-y-6 relative z-10 flex-grow flex flex-col min-h-0">
                    {status === 'idle' && (
                        <div className="flex flex-col gap-4">
                            <div>
                                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">{t('db_sync_pass_label')}</label>
                                <input 
                                    type="password" 
                                    value={password} 
                                    onChange={(e) => setPassword(e.target.value)}
                                    onKeyDown={(e) => e.key === 'Enter' && handleConnect()}
                                    placeholder="••••••••"
                                    className="w-full h-14 bg-slate-800 border-2 border-slate-700 rounded-xl px-4 text-white text-center font-mono text-xl tracking-widest focus:border-[#97bc1e] transition-all outline-none"
                                    autoFocus
                                />
                            </div>
                            <button 
                                onClick={handleConnect}
                                className="w-full py-4 bg-[#97bc1e] hover:bg-[#86a81b] text-white rounded-xl font-black uppercase tracking-widest text-xs shadow-xl transition-all active:scale-95"
                            >
                                {t('db_sync_btn_connect')}
                            </button>
                        </div>
                    )}

                    {status === 'connecting' && (
                        <div className="py-10 text-center space-y-4 flex-grow flex flex-col justify-center">
                            <div className="w-12 h-12 border-4 border-[#97bc1e] border-t-transparent rounded-full animate-spin mx-auto"></div>
                            <p className="text-slate-400 font-bold animate-pulse">{t('db_sync_connecting')}</p>
                        </div>
                    )}

                    {status === 'preview' && (
                        <div className="flex flex-col h-full gap-4">
                            <div className="bg-slate-800/50 rounded-xl border border-slate-700 flex-grow overflow-hidden flex flex-col">
                                <div className="p-3 border-b border-slate-700 bg-slate-800 flex justify-between items-center">
                                    <span className="text-xs font-black text-slate-400 uppercase">Zoznam dielov</span>
                                    <span className="text-xs font-mono font-bold text-[#97bc1e]">{newParts.length} items</span>
                                </div>
                                <div className="overflow-y-auto custom-scrollbar p-2 space-y-1">
                                    {newParts.map((part, idx) => (
                                        <div key={idx} className="flex items-center justify-between p-2 hover:bg-slate-700/50 rounded-lg transition-colors">
                                            <span className="text-sm font-mono font-bold text-white">{part.p}</span>
                                            <span className="text-xs text-slate-500 truncate max-w-[150px]">{part.d}</span>
                                        </div>
                                    ))}
                                    {newParts.length === 0 && (
                                        <p className="text-center text-slate-500 py-4 italic text-sm">Žiadne diely na import</p>
                                    )}
                                </div>
                            </div>

                            <div className="flex-shrink-0 pt-2">
                                <p className="text-white text-center text-sm font-bold mb-4">{t('db_sync_preview', { count: newParts.length })}</p>
                                <button 
                                    onClick={handleImport}
                                    className="w-full py-4 bg-teal-600 hover:bg-teal-500 text-white rounded-xl font-black uppercase tracking-widest text-xs shadow-xl flex items-center justify-center gap-2"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                    </svg>
                                    {t('db_sync_import_btn')}
                                </button>
                            </div>
                        </div>
                    )}

                    {status === 'importing' && (
                        <div className="py-10 text-center space-y-4 flex-grow flex flex-col justify-center">
