                        </div>
                    )}

                    <button 
                        onClick={onClose}
                        className="w-full py-3 text-slate-500 hover:text-slate-300 font-bold uppercase text-[10px] tracking-widest transition-colors flex-shrink-0"
                    >
                        {t('btn_cancel')}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default MasterDbSyncModal;

import { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  orderBy,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  setDoc,
  getDoc,
  arrayUnion,
  writeBatch,
  getDocs
} from 'firebase/firestore';
import { DBItem, MapSector, PartRequest, BOMRequest, BOMComponent, MapObstacle } from '../../types/appTypes';

export const useMasterData = () => {
  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, BOMComponent[]>>({});
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]);
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [mapObstacles, setMapObstacles] = useState<MapObstacle[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);

  useEffect(() => {
    const unsubWp = onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubLogOps = onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), s => setLogisticsOperations(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubSectors = onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
        const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
        setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0)));
    });
    const unsubPartReq = onSnapshot(collection(db, 'part_requests'), s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest))));
    const unsubBomReq = onSnapshot(collection(db, 'bom_requests'), s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest))));

    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (docSnap) => {
        const cleanMap: Record<string, string> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.value) cleanMap[item.value] = item.description || '';
                });
            }
        }
        setPartsMap(cleanMap);
    });

    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (docSnap) => {
        const cleanMap: Record<string, BOMComponent[]> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.parent && item.child) {
                        if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                        cleanMap[item.parent].push({ child: item.child, consumption: item.consumption || 0 });
                    }
                });
            }
        }
        setBomMap(cleanMap);
    });

    const unsubObstacles = onSnapshot(doc(db, 'settings', 'map_layout'), (docSnap) => {
        if (docSnap.exists()) {
            setMapObstacles(docSnap.data().obstacles || []);
        } else {
            setMapObstacles([]);
        }
    });

    return () => { 
        unsubWp(); unsubLogOps(); unsubSectors(); unsubPartReq(); unsubBomReq();
        unsubParts(); unsubBOM(); unsubObstacles();
    };
  }, []);

  // --- ACTIONS ---

  // Obstacles
  const onAddMapObstacle = async (obs: Omit<MapObstacle, 'id'>) => {
      const id = `obs_${Date.now()}`;
      await setDoc(doc(db, 'settings', 'map_layout'), { 
          obstacles: arrayUnion({ ...obs, id }) 
      }, { merge: true });
  };
  const onDeleteMapObstacle = async (id: string) => {
      const ref = doc(db, 'settings', 'map_layout');
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const filtered = (snap.data().obstacles || []).filter((o: any) => o.id !== id);
          await updateDoc(ref, { obstacles: filtered });
      }
  };

  // Workplaces
  const onAddWorkplace = async (val: string, time: number = 0, x: number = 0, y: number = 0) => {
      await addDoc(collection(db, 'workplaces'), { value: val, standardTime: time, coordX: x, coordY: y });
  };
  const onUpdateWorkplace = async (id: string, updates: Partial<DBItem>) => {
      await updateDoc(doc(db, 'workplaces', id), updates);
  };
  const onDeleteWorkplace = async (id: string) => {
      await deleteDoc(doc(db, 'workplaces', id));
  };
  const onDeleteAllWorkplaces = async () => {
      const snap = await getDocs(collection(db, 'workplaces'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };
  const onBatchAddWorkplaces = async (vals: string[]) => {
      const batch = writeBatch(db);
      vals.forEach(line => {
          if (!line.trim()) return;
          const [val, time] = line.split(';');
          const ref = doc(collection(db, 'workplaces'));
          batch.set(ref, { value: val.trim(), standardTime: parseInt(time) || 0 });
      });
      await batch.commit();
  };

  // Logistics Operations
  const onAddLogisticsOperation = async (val: string, time: number = 0, dist: number = 0, x: number = 0, y: number = 0) => { await addDoc(collection(db, 'logistics_operations'), { value: val, standardTime: time, distancePx: dist, coordX: x, coordY: y }); };
  // Fix: changed 'doc(logistics_operations, id)' to 'doc(db, 'logistics_operations', id)' to resolve the 'Cannot find name' error
  const onUpdateLogisticsOperation = async (id: string, updates: Partial<DBItem>) => { await updateDoc(doc(db, 'logistics_operations', id), updates); };
  const onDeleteLogisticsOperation = async (id: string) => { await deleteDoc(doc(db, 'logistics_operations', id)); };
  const onDeleteAllLogisticsOperations = async () => {
      const snap = await getDocs(collection(db, 'logistics_operations'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };

  // Map Sectors
  const onAddMapSector = async (name: string, x: number, y: number, color?: string) => { await addDoc(collection(db, 'map_sectors'), { name, coordX: x, coordY: y, color }); };
  const onUpdateMapSector = async (id: string, updates: Partial<MapSector>) => { await updateDoc(doc(db, 'map_sectors', id), updates); };
  const onDeleteMapSector = async (id: string) => { await deleteDoc(doc(db, 'map_sectors', id)); };

  // Parts (Single Doc Pattern)
  const onAddPart = async (value: string, description: string = '') => {
      try {
          const newItem = { 
            value: value.toUpperCase(), 
            description 
          };
          await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddParts = async (vals: string[]) => {
    try {
      const itemsToAdd: any[] = [];
      vals.forEach((valLine) => {
        if (!valLine.trim()) return;
        const [p, d] = valLine.split(';');
        if(p) { 
          itemsToAdd.push({ 
            value: p.trim().toUpperCase(), 
            description: d ? d.trim() : '' 
          }); 
        }
      });
      if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
    } catch (error) { console.error("Error batch adding parts:", error); throw error; }
  };
  const onDeletePart = async (val: string) => {
      try {
          const ref = doc(db, 'settings', 'parts');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => i.value !== val);
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error("Error deleting part:", e); }
  };
  const onDeleteAllParts = async () => { try { await setDoc(doc(db, 'settings', 'parts'), { items: [] }); } catch (e) { console.error("Error clearing parts:", e); } };

  // BOM (Single Doc Pattern - Optimized for Quota Guard)
  const onAddBOMItem = async (parent: string, child: string, qty: number) => {
      try {
          const newItem = { 
              parent: parent.toUpperCase(), 
              child: child.toUpperCase(), 
              consumption: qty 
          };
          await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddBOMItems = async (vals: string[]) => {
      try {
          const itemsToAdd: any[] = [];
          vals.forEach(line => {
              if (!line.trim()) return;
              const [p, c, q] = line.split(';');
              if (p && c) { 
                  itemsToAdd.push({ 
                      parent: p.trim().toUpperCase(), 
                      child: c.trim().toUpperCase(), 
                      consumption: parseFloat(q?.replace(',', '.') || '0') 
                  }); 
              }
          });
          if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
      } catch (e) { console.error(e); }
  };
  const onDeleteBOMItem = async (parent: string, child: string) => {
      try {
          const ref = doc(db, 'settings', 'bom');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => !(i.parent === parent && i.child === child));
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error(e); }
  };
  const onDeleteAllBOMItems = async () => { try { await setDoc(doc(db, 'settings', 'bom'), { items: [] }); } catch (e) { console.error("Error clearing BOM:", e); } };

  // Requests
  const onRequestPart = async (part: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'part_requests'), { partNumber: part, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeletePartRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'part_requests', id)); } catch(e) { console.error(e); }
  };

  const onRequestBOM = async (parent: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'bom_requests'), { parentPart: parent, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeleteBOMRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'bom_requests', id)); } catch(e) { console.error(e); }
  };

  return {
    partsMap, bomMap, workplaces, logisticsOperations, mapSectors, mapObstacles, partRequests, bomRequests,
    onAddWorkplace, onUpdateWorkplace, onDeleteWorkplace, onDeleteAllWorkplaces, onBatchAddWorkplaces,
    onAddLogisticsOperation, onUpdateLogisticsOperation, onDeleteLogisticsOperation, onDeleteAllLogisticsOperations,
    onAddMapSector, onUpdateMapSector, onDeleteMapSector,
    onAddMapObstacle, onDeleteMapObstacle,
    onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts,
    onAddBOMItem, onBatchAddBOMItems, onDeleteBOMItem, onDeleteAllBOMItems,
    onRequestPart, onDeletePartRequest, 
    onRequestBOM, onDeleteBOMRequest
  };
};

import { MapObstacle } from '../types/appTypes';

export const GRID_SIZE = 20;

export interface Point {
    x: number;
    y: number;
}

/**
 * Vypočíta presnú Manhattan vzdialenosť (v metroch) medzi dvoma bodmi pri zohľadnení prekážok.
 * 10px = 1 meter.
 */
export const calculateAStarDistance = (
    start: Point,
    end: Point,
    obstacles: MapObstacle[] = []
): number => {
    const path = findAStarPath(start, end, obstacles);

    // Ak sa nepodarilo nájsť cestu, vrátime aspoň priamu Manhattan vzdialenosť ako fallback
    if (path.length < 2) {
        return (Math.abs(start.x - end.x) + Math.abs(start.y - end.y)) / 10;
    }

    // Výpočet dĺžky trasy v pixeloch
    let totalDistPx = 0;
    for (let i = 0; i < path.length - 1; i++) {
        totalDistPx += Math.abs(path[i].x - path[i+1].x) + Math.abs(path[i].y - path[i+1].y);
    }

    return totalDistPx / 10; // Prevod na metre
};

/**
 * Jadro A* algoritmu
 */
export const findAStarPath = (
    start: Point,
    end: Point,
    obstacles: MapObstacle[] = []
): Point[] => {
    const startG = { x: Math.round(start.x / GRID_SIZE), y: Math.round(start.y / GRID_SIZE) };
    const endG = { x: Math.round(end.x / GRID_SIZE), y: Math.round(end.y / GRID_SIZE) };

    if (startG.x === endG.x && startG.y === endG.y) return [start, end];

    const isBlocked = (px: number, py: number) => {
        return obstacles.some(o => px >= o.x && px < o.x + o.w && py >= o.y && py < o.y + o.h);
    };

    interface Node {
        x: number;
        y: number;
        g: number;
        f: number;
        path: Point[];
    }

    const openSet: Node[] = [{ 
        ...startG, 
        g: 0, 
        f: Math.abs(startG.x - endG.x) + Math.abs(startG.y - endG.y), 
        path: [start] 
    }];

    const closedSet = new Set<string>();
    let steps = 0;
    const maxSteps = 1500; // Limit pre udržanie výkonu

    while (openSet.length > 0 && steps < maxSteps) {
        steps++;
        openSet.sort((a, b) => a.f - b.f);
        const current = openSet.shift()!;

        if (current.x === endG.x && current.y === endG.y) {
            return [...current.path, end];
        }

        closedSet.add(`${current.x},${current.y}`);

        const neighbors = [
            { x: current.x + 1, y: current.y },
            { x: current.x - 1, y: current.y },
            { x: current.x, y: current.y + 1 },
            { x: current.x, y: current.y - 1 }
        ];

        for (const n of neighbors) {
            if (closedSet.has(`${n.x},${n.y}`)) continue;

            const realX = n.x * GRID_SIZE;
            const realY = n.y * GRID_SIZE;

            if (isBlocked(realX, realY)) continue;

            const g = current.g + 1;
            const h = Math.abs(n.x - endG.x) + Math.abs(n.y - endG.y);
            const f = g + h;

            const existing = openSet.find(o => o.x === n.x && o.y === n.y);
            if (existing && existing.g <= g) continue;

            const newNode = { ...n, g, f, path: [...current.path, { x: realX, y: realY }] };
            if (!existing) openSet.push(newNode);
            else {
                existing.g = g;
                existing.f = f;
                existing.path = newNode.path;
            }
        }
    }
    return []; // Cesta nenájdená
};

import { useMemo } from 'react';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig, MapObstacle } from '../types/appTypes';
import { calculateAStarDistance } from '../utils/pathfinding';

export type FilterMode = 'TODAY' | 'YESTERDAY' | 'WEEK' | 'MONTH' | 'CUSTOM';
export type SourceFilter = 'ALL' | 'PROD' | 'LOG';
export type ShiftFilter = 'ALL' | 'DAY' | 'NIGHT';

export interface AnalyticsFilters {
  mode: FilterMode;
  source: SourceFilter;
  shift: ShiftFilter;
  customStart?: string;
  customEnd?: string;
}

export interface DrivingStats {
    fullDist: number;   // metre
    emptyDist: number;  // metre
    fullRides: number;  
    emptyRides: number; 
    efficiency: number; 
}

export interface WorkerStats {
  id: string;
  name: string;
  index: number;
  tasksDone: number;
  pureWorkMinutes: number;
  utilizationPercent: number;
  performanceRatio: number;
  avgReactionSeconds: number;
  fullDistMeters: number;
  emptyDistMeters: number;
  logEfficiency: number;
  confidenceRating: number;
  totalRides: number; 
  invalidTasksCount: number;
}

export const useAnalyticsEngine = (
  tasks: Task[],
  archivedTasks: Task[],
  systemBreaks: SystemBreak[],
  mapSectors: MapSector[],
  workplaces: DBItem[],
  logisticsOperations: DBItem[],
  mapObstacles: MapObstacle[], // PRIDANÉ
  systemConfig: SystemConfig,
  filters: AnalyticsFilters,
  resolveName: (username?: string | null) => string
) => {

  const combinedData = useMemo(() => {
    const allTasks = [...tasks, ...archivedTasks];
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayTs = today.getTime();

    return allTasks.filter(task => {
      const referenceTime = task.completedAt || task.createdAt || 0;
      if (!referenceTime) return false;

      let timeMatch = false;
      switch (filters.mode) {
        case 'TODAY': timeMatch = referenceTime >= todayTs; break;
        case 'YESTERDAY': timeMatch = referenceTime >= (todayTs - 86400000) && referenceTime < todayTs; break;
        case 'WEEK': timeMatch = referenceTime >= (todayTs - (today.getDay() || 7 - 1) * 86400000); break;
        case 'MONTH': timeMatch = referenceTime >= new Date(today.getFullYear(), today.getMonth(), 1).getTime(); break;
        case 'CUSTOM':
          if (!filters.customStart || !filters.customEnd) return false;
          const startTs = new Date(filters.customStart).getTime();
          const endTs = new Date(filters.customEnd).getTime() + 86399999;
          timeMatch = referenceTime >= startTs && referenceTime <= endTs;
          break;
        default: timeMatch = true;
      }
      if (!timeMatch) return false;

      if (filters.source === 'PROD' && !task.isProduction && task.isLogistics) return false;
      if (filters.source === 'LOG' && !task.isLogistics) return false;

      if (filters.shift !== 'ALL') {
        const hour = new Date(referenceTime).getHours();
        const isDay = hour >= 6 && hour < 18;
        if (filters.shift === 'DAY' && !isDay) return false;
        if (filters.shift === 'NIGHT' && isDay) return false;
      }

      return true;
    });
  }, [tasks, archivedTasks, filters]);

  const engineResult = useMemo(() => {
    const VZV_SPEED_KMH = systemConfig.vzvSpeed || 8;
    const VZV_SPEED_MPM = (VZV_SPEED_KMH * 1000) / 60;
    const VZV_SPEED_MPS = VZV_SPEED_KMH / 3.6;

    const SHIFT_MINUTES = 450;

    // --- DISTANCE MATRIX CACHE (PREVENCIA MRZNUTIA) ---
    const distanceCache = new Map<string, number>();
    const getCachedAStarDistance = (p1: {x: number, y: number}, p2: {x: number, y: number}, id1: string, id2: string) => {
        const cacheKey = id1 < id2 ? `${id1}_${id2}` : `${id2}_${id1}`;
        if (distanceCache.has(cacheKey)) return distanceCache.get(cacheKey)!;
        const d = calculateAStarDistance(p1, p2, mapObstacles);
        distanceCache.set(cacheKey, d);
        return d;
    };

    const workerTaskMap: Record<string, Task[]> = {};
    const hourlyLoad: Record<number, { prod: number, log: number }> = {};
    for (let h = 5; h <= 23; h++) { hourlyLoad[h] = { prod: 0, log: 0 }; }

    const workplaceLoad: Record<string, { load: number, pal: number, req: number }> = {};
    const highRunnerLoad: Record<string, { load: number, pal: number, req: number }> = {};
    const missingPartsMap: Record<string, number> = {};

    let globalRealErrors = 0;
    let globalFalseAlarms = 0;
    let globalAuditedCount = 0;

    let globalTotalTargetMin = 0;
    let globalTotalActualMin = 0;

    const prodDriving: DrivingStats = { fullDist: 0, emptyDist: 0, fullRides: 0, emptyRides: 0, efficiency: 0 };
    const logDriving: DrivingStats = { fullDist: 0, emptyDist: 0, fullRides: 0, emptyRides: 0, efficiency: 0 };

    combinedData.forEach(t => {
      if (t.isDone && t.completedBy) {
        if (!workerTaskMap[t.completedBy]) workerTaskMap[t.completedBy] = [];
        workerTaskMap[t.completedBy].push(t);
      }

      const refTime = t.completedAt || t.createdAt || 0;
      const hour = new Date(refTime).getHours();

      if (hour >= 5 && hour <= 23) {
        const points = (t.quantityUnit === 'pallet' ? parseFloat((t.quantity || '0').replace(',', '.')) : 1) || 1;
        if (t.isLogistics) hourlyLoad[hour].log += points; 
        else hourlyLoad[hour].prod += points;
      }

      if (t.auditResult) {
        globalAuditedCount++;
        if (t.auditResult === 'NOK') globalRealErrors++;
        else globalFalseAlarms++;
      }
      if (t.isMissing && t.partNumber) {
        missingPartsMap[t.partNumber] = (missingPartsMap[t.partNumber] || 0) + 1;
      }
    });

    const calculateBlockedTime = (history: any[] | undefined, startTime: number, endTime: number): number => {
      let totalBlocked = 0;
      systemBreaks.forEach(br => {
        const overlapStart = Math.max(startTime, br.start);
        const overlapEnd = Math.min(endTime, br.end || endTime);
        if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
      });
      return totalBlocked;
    };

    const workerStatsList: WorkerStats[] = Object.entries(workerTaskMap).map(([uid, workerTasks]) => {
      const sorted = [...workerTasks].sort((a, b) => (a.completedAt || 0) - (b.completedAt || 0));

      let wFullDist = 0;
      let wEmptyDist = 0;
      let wTransitDist = 0;
      let wExecMs = 0;
      let wTargetMinTotal = 0;
      let wActualMinTotal = 0;
      let wReactMs = 0;
      let wReactCount = 0;
      let wMissingReported = 0;
      let wRealErrors = 0;
      let wRides = 0; 
      let wInvalidTasks = 0;
      const daysWorked = new Set<string>();

      let lastPoint: { x: number, y: number, id: string } | null = null;

      sorted.forEach(task => {
        if (task.completedAt) daysWorked.add(new Date(task.completedAt).toLocaleDateString());

        const qtyVal = parseFloat((task.quantity || '1').replace(',', '.'));
        const loadMultiplier = (task.quantityUnit === 'pallet') ? qtyVal : 1;
        const points = loadMultiplier;

        if (!task.isLogistics) {
            if (task.workplace) {
              if (!workplaceLoad[task.workplace]) workplaceLoad[task.workplace] = { load: 0, pal: 0, req: 0 };
              workplaceLoad[task.workplace].load += points; workplaceLoad[task.workplace].req++;
              if (task.quantityUnit === 'pallet') workplaceLoad[task.workplace].pal += qtyVal;
            }
            if (task.partNumber) {
              if (!highRunnerLoad[task.partNumber]) highRunnerLoad[task.partNumber] = { load: 0, pal: 0, req: 0 };
              highRunnerLoad[task.partNumber].load += points; highRunnerLoad[task.partNumber].req++;
              if (task.quantityUnit === 'pallet') highRunnerLoad[task.partNumber].pal += qtyVal;
            }
        }

        let targetMin = 0;
        let oneWayD = 0;

        if (task.isLogistics) {
            const logOp = logisticsOperations.find(o => o.value === task.workplace);
            if (logOp) {
                oneWayD = logOp.distancePx ? (logOp.distancePx / 10) : 0;

                if (lastPoint && logOp.coordX !== undefined) {
                    // Tranzit k rampe (A*)
                    const transitMeters = getCachedAStarDistance(
                        { x: lastPoint.x, y: lastPoint.y },
                        { x: logOp.coordX, y: logOp.coordY || 0 },
                        lastPoint.id,
                        logOp.id
                    );
                    wTransitDist += transitMeters;
                }

                const standardTime = logOp.standardTime || 2.0;
                const travelTimeMin = oneWayD / VZV_SPEED_MPM; 
                targetMin = (standardTime * loadMultiplier) + travelTimeMin;

                if (logOp.coordX !== undefined) {
                    lastPoint = { x: logOp.coordX, y: logOp.coordY || 0, id: logOp.id };
                } else lastPoint = null;
            }
        } else {
            const wp = workplaces.find(w => w.value === task.workplace);
            if (wp) {
                let startPoint: {x: number, y: number, id: string} | null = null;
                if (task.pickedFromSectorId) {
                    const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
                    if (sector) startPoint = { x: sector.coordX, y: sector.coordY, id: sector.id };
                }

                if (lastPoint && startPoint) {
                    // Tranzit medzi pracoviskom a novým sektorom (A*)
                    const transitMeters = getCachedAStarDistance(
                        { x: lastPoint.x, y: lastPoint.y },
                        { x: startPoint.x, y: startPoint.y },
                        lastPoint.id,
                        startPoint.id
                    );
                    wTransitDist += transitMeters;
                }

                if (startPoint) {
                    // Cesta zo sektora na pracovisko (A*)
                    oneWayD = getCachedAStarDistance(
                        { x: startPoint.x, y: startPoint.y },
                        { x: wp.coordX || 0, y: wp.coordY || 0 },
                        startPoint.id,
                        wp.id
                    );
                }

                const standardTime = wp.standardTime || 2.0;
                const travelTimeMin = oneWayD / VZV_SPEED_MPM;
                targetMin = (standardTime * loadMultiplier) + travelTimeMin;
                lastPoint = { x: wp.coordX || 0, y: wp.coordY || 0, id: wp.id };
            } else {
                targetMin = 2 * loadMultiplier; 
                lastPoint = null;
            }
        }

        if (task.startedAt && task.completedAt) {
          const rawExecMs = task.completedAt - task.startedAt;
          const blockedMs = calculateBlockedTime(task.inventoryHistory, task.startedAt, task.completedAt);
          const realExecMs = Math.max(rawExecMs - blockedMs, 0);
          const actualMin = realExecMs / 60000;

          if (actualMin < 0.5) {
              task.isInvalid = true; 
              wInvalidTasks++;
              wExecMs += realExecMs;
          } else {
              const flooredActual = Math.max(actualMin, 1.0); 
              wActualMinTotal += flooredActual;
              wTargetMinTotal += targetMin;
              globalTotalActualMin += flooredActual;
              globalTotalTargetMin += targetMin;
              wExecMs += realExecMs;
          }
        }

        if (oneWayD > 0) {
            const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
            const possibleTrips = Math.round(((durationMs / 1000) * VZV_SPEED_MPS) / (2 * oneWayD)); 
            const validatedTrips = Math.min(Math.max(1, Math.floor(loadMultiplier)), Math.max(1, possibleTrips));

            if (validatedTrips > 0) {
                const fullD = validatedTrips * oneWayD;
                const emptyD = (validatedTrips > 1 ? (validatedTrips - 1) * oneWayD : 0);

                wFullDist += fullD;
                wEmptyDist += emptyD;
                wRides += (validatedTrips * 2 - 1);

                if (task.isLogistics) {
                    logDriving.fullDist += fullD; logDriving.emptyDist += emptyD;
                    logDriving.fullRides += validatedTrips;
                    logDriving.emptyRides += (validatedTrips > 1 ? validatedTrips - 1 : 0);
                } else {
                    prodDriving.fullDist += fullD; prodDriving.emptyDist += emptyD;
                    prodDriving.fullRides += validatedTrips;
                    prodDriving.emptyRides += (validatedTrips > 1 ? validatedTrips - 1 : 0);
                }
            }
        } else wRides++;

        if (task.createdAt && task.startedAt) {
          const react = task.startedAt - task.createdAt;
          if (react > 0) { wReactMs += react; wReactCount++; }
        }
        if (task.isMissing) {
          wMissingReported++;
          if (task.auditResult === 'NOK') wRealErrors++;
        }
      });

      const nDays = Math.max(daysWorked.size, 1);
      const pureMin = wExecMs / 60000;
      const utilization = (pureMin * 1.15 / (nDays * SHIFT_MINUTES)) * 100;
      const perf = wActualMinTotal > 0 ? Math.min((wTargetMinTotal / wActualMinTotal) * 100, 200) : 0;
      const reactSec = wReactCount > 0 ? (wReactMs / wReactCount) / 1000 : 0;
      const conf = wMissingReported > 0 ? ((wMissingReported - wRealErrors) / wMissingReported) * 100 : 100;
      const totalEmpty = wEmptyDist + wTransitDist;
      const logEff = (wFullDist + totalEmpty) > 0 ? (wFullDist / (wFullDist + totalEmpty)) * 100 : 50;

      const sQual = (conf / 100) * 3.0;
      const sUtil = (Math.min(utilization, 100) / 100) * 2.5;
      const sStd = Math.min(perf, 200) / 200 * 2.0;
      const sReac = reactSec > 0 ? (reactSec < 60 ? 1.0 : reactSec < 180 ? 0.5 : 0) : 0.5;
      const sLog = (logEff / 100) * 1.0;

      return {
        id: uid, name: resolveName(uid), index: parseFloat((sQual + sUtil + sStd + sReac + sLog).toFixed(1)),
        tasksDone: workerTasks.length, pureWorkMinutes: pureMin,
        utilizationPercent: utilization, performanceRatio: perf,
        avgReactionSeconds: reactSec, fullDistMeters: wFullDist,
        emptyDistMeters: totalEmpty, logEfficiency: logEff, confidenceRating: conf,
        totalRides: wRides, invalidTasksCount: wInvalidTasks
      };
    });

    prodDriving.efficiency = (prodDriving.fullDist + prodDriving.emptyDist) > 0 ? (prodDriving.fullDist / (prodDriving.fullDist + prodDriving.emptyDist)) * 100 : 0;
    logDriving.efficiency = (logDriving.fullDist + logDriving.emptyDist) > 0 ? (logDriving.fullDist / (logDriving.fullDist + logDriving.emptyDist)) * 100 : 0;

    const totalFullDistGlobal = prodDriving.fullDist + logDriving.fullDist;
    const totalEmptyDistGlobal = prodDriving.emptyDist + logDriving.emptyDist;

    return {
      filteredTasks: combinedData,
      globalStats: {
        totalTasks: combinedData.length,
        totalDone: combinedData.filter(t => t.isDone).length,
        totalFullDist: totalFullDistGlobal,
        totalEmptyDist: totalEmptyDistGlobal,
        globalEfficiency: (totalFullDistGlobal + totalEmptyDistGlobal) > 0 ? (totalFullDistGlobal / (totalFullDistGlobal + totalEmptyDistGlobal)) * 100 : 0,
        globalPerformanceRatio: globalTotalActualMin > 0 ? Math.min((globalTotalTargetMin / globalTotalActualMin) * 100, 200) : 0,
        totalVolume: combinedData.reduce((a, b) => a + (parseFloat((b.quantity || '0').replace(',', '.')) || 0), 0),
        totalPhysicalRides: workerStatsList.reduce((a, b) => a + b.totalRides, 0)
      },
      drivingStats: { production: prodDriving, logistics: logDriving },
      workerStats: workerStatsList,
      charts: {
        hourly: Object.entries(hourlyLoad).map(([h, d]) => ({ hour: parseInt(h), label: `${h}h`, production: d.prod, logistics: d.log })).sort((a,b) => a.hour - b.hour),
        highRunners: Object.entries(highRunnerLoad).map(([k, v]) => ({ partNumber: k, ...v, totalTasks: v.req, taskRequests: v.req })).sort((a,b) => b.load - a.load).slice(0, 3),
        workplaces: Object.entries(workplaceLoad).map(([k, v]) => ({ workplace: k, ...v, totalTasks: v.req, taskRequests: v.req })).sort((a,b) => b.load - a.load).slice(0, 3)
      },
      qualityStats: {
        realErrorsCount: globalRealErrors,
        falseAlarmsCount: globalFalseAlarms,
        totalAuditedMissing: globalAuditedCount,
        topMissingParts: Object.entries(missingPartsMap).map(([p, c]) => ({ partNumber: p, count: c })).sort((a,b) => b.count - a.count).slice(0, 3)
      }
    };
  }, [combinedData, systemBreaks, mapSectors, workplaces, logisticsOperations, mapObstacles, systemConfig, resolveName]);

  return engineResult;
};

import React, { useMemo, useState, useEffect } from 'react';
import { Task, SystemConfig } from '../../../types/appTypes';
import { useLanguage } from '../../LanguageContext';
import AnalyticsExportPanel from './AnalyticsExportPanel';
import HighRunnerSection from './HighRunnerSection';
import HourlyChartSection from './HourlyChartSection';
import QualityAuditSection from './QualityAuditSection';
import WorkerDetailModal from './WorkerDetailModal';
import DrivingMetrics from './DrivingMetrics';
import { useAnalyticsEngine, FilterMode, SourceFilter, ShiftFilter } from '../../../hooks/useAnalyticsEngine';
import { useData } from '../../../context/DataContext';

interface AnalyticsTabProps {
  systemConfig: SystemConfig;
  currentUser: string;
  currentUserRole: string;
  hasPermission: (permName: string) => boolean;
}

const AnalyticsTab: React.FC<AnalyticsTabProps> = ({ 
  systemConfig, currentUser, currentUserRole 
}) => {
  const data = useData(); 

  const [filterMode, setFilterMode] = useState<FilterMode>('TODAY');
  const [sourceFilter, setSourceFilter] = useState<SourceFilter>('ALL');
  const [shiftFilter, setShiftFilter] = useState<ShiftFilter>('ALL');
  const [customStart, setCustomStart] = useState('');
  const [customEnd, setCustomEnd] = useState('');
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [historicalArchive, setHistoricalArchive] = useState<Task[]>([]);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);
  const [selectedWorkerData, setSelectedWorkerData] = useState<{ name: string; tasks: Task[] } | null>(null);
  const { t, language } = useLanguage();

  const now = new Date();
  const firstDayOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
  const lastDayOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];

  const resolveName = (username?: string | null) => {
      if (!username) return '-';
      const u = data.users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  };

  const canExport = useMemo(() => {
    return currentUserRole === 'ADMIN' || (data.users?.find(u => u.username === currentUser)?.canExportAnalytics === true);
  }, [currentUser, currentUserRole, data.users]);

  useEffect(() => {
    const loadHistory = async () => {
      setIsLoadingHistory(true);
      try {
        const sanons = await data.fetchSanons();
        const allArchivedTasks: Task[] = [];
        sanons.forEach(sanon => {
          if (sanon.tasks && Array.isArray(sanon.tasks)) {
            allArchivedTasks.push(...sanon.tasks);
          }
        });
        setHistoricalArchive(allArchivedTasks);
      } catch (err) {
        console.error("Failed to load historical archives", err);
      } finally {
        setIsLoadingHistory(false);
      }
    };
    loadHistory();
  }, [data.fetchSanons]);

  const masterDataset = useMemo(() => {
    const live = Array.isArray(data.tasks) ? data.tasks : [];
    const draft = Array.isArray(data.draftTasks) ? data.draftTasks : [];
    const archive = Array.isArray(historicalArchive) ? historicalArchive : [];
    const combined = [...live, ...draft, ...archive];
    const uniqueMap = new Map();
    combined.forEach(task => { if (task && task.id) uniqueMap.set(task.id, task); });
    return Array.from(uniqueMap.values());
  }, [data.tasks, data.draftTasks, historicalArchive]);

  const engine = useAnalyticsEngine(
    masterDataset,
    [],
    data.systemBreaks,
    data.mapSectors,
    data.workplaces,
    data.logisticsOperations,
    data.mapObstacles, // PRIDANÉ
    systemConfig,
    {
      mode: filterMode,
      source: sourceFilter,
      shift: shiftFilter,
      customStart,
      customEnd
    },
    resolveName
  );

  const { filteredTasks, globalStats, qualityStats, drivingStats } = engine;

  // POMOCNÁ FUNKCIA PRE BLOKOVANÝ ČAS
  const calculateBlockedTime = (startTime: number, endTime: number): number => {
    let totalBlocked = 0;
    data.systemBreaks.forEach(br => {
      const overlapStart = Math.max(startTime, br.start);
      const overlapEnd = Math.min(endTime, br.end || endTime);
      if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
    });
    return totalBlocked;
  };

  const workerTableData = useMemo(() => {
    const workers: Record<string, { id: string; netMs: number; rides: number; sumPerf: number; countPerf: number }> = {};
    filteredTasks.forEach(task => {
        if (!task.isDone || !task.completedBy) return;
        if (!workers[task.completedBy]) workers[task.completedBy] = { id: task.completedBy, netMs: 0, rides: 0, sumPerf: 0, countPerf: 0 };
        const w = workers[task.completedBy];
        w.rides++; 
        if (task.startedAt && task.completedAt) {
            const rawDurationMs = task.completedAt - task.startedAt;
            const blockedMs = calculateBlockedTime(task.startedAt, task.completedAt);
            const pureMs = Math.max(rawDurationMs - blockedMs, 0);
            w.netMs += pureMs;
            // Výpočet výkonnosti v tabuľke teraz zohľadňuje presné A* dáta z enginu
            const targetMin = task.standardTime || 2.0; // Predpokladáme predpočítanú normu z enginu (alebo fallback)
            const durationMin = pureMs / 60000;
            let adjMin = durationMin < 0.5 ? 2 : Math.max(durationMin, 1);
            if (targetMin > 0) {
                w.sumPerf += Math.min((targetMin / adjMin) * 100, 200);
                w.countPerf++;
            }
        }
    });
    return Object.values(workers).map(w => ({
        id: w.id, name: resolveName(w.id), netMs: w.netMs, rides: w.rides,
        efficiency: w.countPerf > 0 ? w.sumPerf / w.countPerf : 0
    })).sort((a, b) => b.efficiency - a.efficiency);
  }, [filteredTasks]);

  const formatNetTime = (ms: number) => {
    const h = Math.floor(ms / 3600000);
    const m = Math.floor((ms % 3600000) / 60000);
    const s = Math.floor((ms % 60000) / 1000);
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-20 animate-fade-in text-slate-200">
      <div className="flex justify-between items-center">
        <h1 className="text-2xl sm:text-3xl font-black text-teal-400 uppercase tracking-tighter">{t('analytics_title')}</h1>
        {isLoadingHistory && (
          <div className="flex items-center gap-2 px-4 py-1.5 bg-teal-500/10 border border-teal-500/20 rounded-full animate-pulse">
            <div className="w-1.5 h-1.5 bg-teal-500 rounded-full"></div>
            <span className="text-[10px] font-black text-teal-500 uppercase tracking-widest">Načítavam archívy...</span>
          </div>
        )}
      </div>

      <AnalyticsExportPanel canExport={canExport} tasks={filteredTasks} systemBreaks={data.systemBreaks} resolveName={resolveName} t={t} language={language} />

      <div className="bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl overflow-hidden mb-8 flex flex-col">
        <button onClick={() => setIsFilterOpen(!isFilterOpen)} className="w-full flex items-center justify-between p-6 bg-slate-800/40 hover:bg-slate-800/60 transition-colors border-b border-slate-800/50">
          <div className="flex items-center gap-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-teal-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>
            <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">FILTRÁCIA DÁT</h3>
          </div>
          <div className={`transition-transform duration-300 ${isFilterOpen ? 'rotate-180' : ''}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg></div>
        </button>

        {isFilterOpen && (
          <div className="p-8 space-y-8 animate-fade-in">
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">Časový Rozsah</label>
              <div className="grid grid-cols-2 md:grid-cols-5 gap-2">
                {(['TODAY', 'YESTERDAY', 'WEEK', 'MONTH', 'CUSTOM'] as FilterMode[]).map(m => (
                  <button key={m} onClick={() => setFilterMode(m)} className={`h-11 px-4 rounded-xl text-[10px] font-black uppercase transition-all border-2 ${filterMode === m ? 'bg-amber-500/10 border-amber-500 text-amber-500 shadow-lg shadow-amber-500/10' : 'bg-slate-800/50 border-slate-800 text-slate-500 hover:text-slate-300'}`}>{t(`filter_${m.toLowerCase()}` as any)}</button>
                ))}
              </div>
              {filterMode === 'CUSTOM' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-4 animate-fade-in">
                  <input type="date" value={customStart} onChange={e => setCustomStart(e.target.value)} className="w-full h-12 bg-slate-950 border-2 border-slate-800 rounded-xl px-4 text-white text-sm focus:border-amber-500 transition-all outline-none" />
                  <input type="date" value={customEnd} onChange={e => setCustomEnd(e.target.value)} className="w-full h-12 bg-slate-950 border-2 border-slate-800 rounded-xl px-4 text-white text-sm focus:border-amber-500 transition-all outline-none" />
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-slate-900/60 p-5 rounded-2xl border border-slate-800 border-l-4 border-l-blue-500 shadow-xl">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">CELKOVO ÚLOH</p>
          <p className="text-3xl font-black text-white mt-2 font-mono">{globalStats.totalTasks}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl border border-slate-800 border-l-4 border-l-purple-500 shadow-xl">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">REALNE JAZDY</p>
          <p className="text-3xl font-black text-white mt-2 font-mono">{globalStats.totalPhysicalRides}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl border border-slate-800 border-l-4 border-l-amber-500 shadow-xl">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">A* NAJAZDENÉ</p>
          <p className="text-3xl font-black text-white mt-2 font-mono">{(globalStats.totalFullDist/1000).toFixed(1)} km</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl border border-slate-800 border-l-4 border-l-teal-500 shadow-xl">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">EFEKTIVITA TRÁS</p>
          <p className="text-3xl font-black text-white mt-2 font-mono">{globalStats.globalEfficiency.toFixed(1)}%</p>
        </div>
      </div>

      {/* WORKER TABLE */}
      <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl shadow-2xl overflow-hidden">
          <div className="flex items-center gap-3 mb-8 border-b border-white/5 pb-6">
              <div className="w-1.5 h-6 bg-purple-500 rounded-full"></div>
              <h3 className="text-sm font-black text-white uppercase tracking-[0.25em]">{t('table_title')}</h3>
          </div>
          <div className="overflow-x-auto custom-scrollbar">
              <table className="w-full text-left border-collapse min-w-[600px]">
                  <thead>
                      <tr className="bg-slate-950/50 text-slate-500 text-[10px] font-black uppercase tracking-[0.2em]">
                          <th className="py-4 px-6 text-center w-16">{t('th_rank')}</th>
                          <th className="py-4 px-6">{t('username')}</th>
                          <th className="py-4 px-6 text-center">{t('th_work_time')}</th>
                          <th className="py-4 px-6 text-center">JAZDY</th>
                          <th className="py-4 px-6 text-right">{t('kpi_effic')}</th>
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-800/50">
                      {workerTableData.map((w, idx) => (
                          <tr key={w.id} className="hover:bg-white/[0.03] transition-colors">
                              <td className="py-5 px-6 text-center"><div className="w-10 h-10 rounded-lg font-black text-xl bg-slate-800 border border-slate-700 text-slate-500 flex items-center justify-center mx-auto">{idx + 1}</div></td>
                              <td className="py-5 px-6">
                                  <button onClick={() => setSelectedWorkerData({ name: w.name, tasks: masterDataset.filter(t => t.completedBy === w.id) })} className="text-base font-black text-teal-400 hover:underline uppercase">{w.name}</button>
                              </td>
                              <td className="py-5 px-6 text-center font-mono text-slate-300">{formatNetTime(w.netMs)}</td>
                              <td className="py-5 px-6 text-center font-black text-white">{w.rides}</td>
                              <td className="py-5 px-6 text-right font-black font-mono text-teal-400">{w.efficiency.toFixed(1)}%</td>
                          </tr>
                      ))}
                  </tbody>
              </table>
          </div>
      </div>

      <HighRunnerSection topHighRunners={engine.charts.highRunners} topWorkplaces={engine.charts.workplaces} t={t} />
      <HourlyChartSection hourlyData={engine.charts.hourly} t={t} />
      <DrivingMetrics productionStats={drivingStats.production} logisticsStats={drivingStats.logistics} vzvSpeed={systemConfig.vzvSpeed || 8} />
      <QualityAuditSection data={qualityStats} t={t} />

      {selectedWorkerData && (
        <WorkerDetailModal name={selectedWorkerData.name} tasks={selectedWorkerData.tasks} periodLabel={filterMode} systemBreaks={data.systemBreaks} onClose={() => setSelectedWorkerData(null)} mapSectors={data.mapSectors} workplaces={data.workplaces} systemConfig={systemConfig} logisticsOperations={data.logisticsOperations} />
      )}
    </div>
  );
};

