import { coreTranslations } from './locales/core';
import { taskTranslations } from './locales/tasks';
import { analyticsTranslations } from './locales/analytics';
import { adminTranslations } from './locales/admin';

export const translations = {
  sk: {
    ...coreTranslations.sk,
    ...taskTranslations.sk,
    ...analyticsTranslations.sk,
    ...adminTranslations.sk
  },
  en: {
    ...coreTranslations.en,
    ...taskTranslations.en,
    ...analyticsTranslations.en,
    ...adminTranslations.en
  }
};

export type AppTranslationKey = keyof typeof translations.sk;

import React, { createContext, useState, useContext, useEffect } from 'react';
import { translations, AppTranslationKey } from '../data/locales';

type Language = 'sk' | 'en';

interface LanguageContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (key: AppTranslationKey, params?: Record<string, string | number>) => string;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const LanguageProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguage] = useState<Language>('sk');

  useEffect(() => {
    const storedLang = localStorage.getItem('app_language');
    if (storedLang === 'en' || storedLang === 'sk') {
      setLanguage(storedLang as Language);
    }
  }, []);

  const changeLanguage = (lang: Language) => {
    setLanguage(lang);
    localStorage.setItem('app_language', lang);
  };

  const t = (key: AppTranslationKey, params?: Record<string, string | number>) => {
    const dict = translations[language] as Record<string, string>;
    let text = dict[key] || (key as string);

    if (params) {
      Object.entries(params).forEach(([k, v]) => {
        text = text.replace(`{${k}}`, String(v));
      });
    }
    return text;
  };

  return (
    <LanguageContext.Provider value={{ language, setLanguage: changeLanguage, t }}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
};

