declare var XLSX: any;

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
);

const InventoryTab: React.FC<InventoryTabProps> = ({ currentUser, tasks, onAddTask, onUpdateTask, onDeleteTask, parts, onRequestPart, resolveName }) => {
    const { t, language } = useLanguage();

    const locationRef = useRef<HTMLInputElement>(null);
    const partRef = useRef<HTMLInputElement>(null);
    const batchRef = useRef<HTMLInputElement>(null);
    const quantityRef = useRef<HTMLInputElement>(null);

    const [location, setLocation] = useState('');
    const [partNumber, setPartNumber] = useState('');
    const [batch, setBatch] = useState('');
    const [isBatchMissing, setIsBatchMissing] = useState(false);
    const [quantity, setQuantity] = useState('');
    const [lastSaved, setLastSaved] = useState<number | null>(null);
    const [scannedItems, setScannedItems] = useState<ScannedItem[]>([]);

    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: React.ReactNode;
        onConfirm: () => void;
        type: 'danger' | 'warning';
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => {},
        type: 'danger'
    });

    const activeInventoryTask = useMemo(() => {
        return (tasks || []).find(t => 
            t.partNumber === "Počítanie zásob" && 
            !t.isDone && 
            t.inProgressBy === currentUser
        );
    }, [tasks, currentUser]);

    useEffect(() => {
        const saved = localStorage.getItem('inventory_scans');
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                if (parsed && Array.isArray(parsed)) {
                    setScannedItems(parsed);
                    if (parsed.length > 0) setLastSaved(parsed[0].timestamp);
                }
            } catch (e) {
                console.error("Failed to parse inventory scans", e);
            }
        }
    }, []);

    useEffect(() => {
        if (scannedItems && scannedItems.length > 0) {
            localStorage.setItem('inventory_scans', JSON.stringify(scannedItems));
            setLastSaved(Date.now());
        }
    }, [scannedItems]);

    const handleStartInventory = () => {
        onAddTask("Počítanie zásob", "Inventúra", "0", "pallet", "NORMAL", true);
    };

    const handleAddItem = () => {
        const isLocEmpty = !location.trim();
        const isPartEmpty = !partNumber.trim();
        const isQtyEmpty = !quantity.trim();
        const isBatchRequiredAndEmpty = !isBatchMissing && !batch.trim();

        if (isLocEmpty || isPartEmpty || isQtyEmpty || isBatchRequiredAndEmpty) {
            const missingFields = [];
            if (isLocEmpty) missingFields.push(t('inv_location_label'));
            if (isPartEmpty) missingFields.push(t('part_number'));
            if (isBatchRequiredAndEmpty) missingFields.push("Batch");
            if (isQtyEmpty) missingFields.push(t('quantity'));

            const errorMsg = language === 'sk' 
                ? `Prosím, vyplňte povinné polia: ${missingFields.join(', ')}.` 
                : `Please fill required fields: ${missingFields.join(', ')}.`;

            alert(errorMsg);
            return;
        }

        const newItem: ScannedItem = {
            id: crypto.randomUUID(),
            location,
            partNumber,
            batch: isBatchMissing ? `[${t('inv_label_missing').toUpperCase()}]` : batch,
            quantity,
            timestamp: Date.now(),
            worker: currentUser
        };
        setScannedItems([newItem, ...scannedItems]);

        setLocation(''); 
        setPartNumber(''); 
        setBatch(''); 
        setIsBatchMissing(false);
        setQuantity('');
        setTimeout(() => locationRef.current?.focus(), 10);
    };

    const handleDeleteItem = (id: string) => {
        setConfirmModal({
            isOpen: true,
            title: t('inv_confirm_delete_title'),
            message: t('inv_confirm_delete_msg'),
            type: 'danger',
            onConfirm: () => {
                const updated = scannedItems.filter(item => item.id !== id);
                setScannedItems(updated);
                if (updated.length === 0) {
                    localStorage.removeItem('inventory_scans');
                }
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleClearAll = () => {
        setConfirmModal({
            isOpen: true,
            title: t('inv_confirm_clear_title'),
            message: t('inv_confirm_clear_msg'),
            type: 'danger',
            onConfirm: () => {
                setScannedItems([]);
                localStorage.removeItem('inventory_scans');
                setLastSaved(null);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleCancelInventory = () => {
        setConfirmModal({
            isOpen: true,
            title: t('inv_confirm_cancel_title'),
            message: (
                <div className="space-y-4">
                    <p className="font-bold text-red-500">
                        {t('inv_confirm_cancel_warning')}
                    </p>
                    <div className="bg-gray-700/50 p-4 rounded-lg border border-gray-600 text-sm">
                        <p className="text-gray-300">
                            {t('inv_confirm_cancel_hint')}
                            <span className="text-green-400 font-black ml-1">"EXPORT & UKONČIŤ"</span>.
                        </p>
                    </div>
                </div>
            ),
            type: 'danger',
            onConfirm: () => {
                if (activeInventoryTask) {
                    onDeleteTask(activeInventoryTask.id);
                }
                setScannedItems([]);
                localStorage.removeItem('inventory_scans');
                setLastSaved(null);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleExportAndFinish = () => {
        if (!scannedItems || scannedItems.length === 0) {
            alert(language === 'sk' ? "Zoznam je prázdny." : "List is empty.");
            return;
        }

        handleExport();

        const finalCount = scannedItems.length.toString();

        if (activeInventoryTask) {
            onUpdateTask(activeInventoryTask.id, { 
                isDone: true, 
                status: 'completed', 
                completionTime: new Date().toLocaleTimeString('sk-SK'),
                completedBy: currentUser,
                completedAt: Date.now(),
                isInProgress: false,
                inProgressBy: null,
                quantity: finalCount
            });
        }

        setScannedItems([]);
        localStorage.removeItem('inventory_scans');
        setLastSaved(null);
    };

    const handleExport = () => {
        if (!scannedItems || scannedItems.length === 0) return;
        if (typeof XLSX === 'undefined') { alert("Library Error"); return; }
        const data = scannedItems.map(item => ({
            "Dátum inventúry": new Date(item.timestamp).toLocaleDateString('sk-SK'),
            "Užívateľ": resolveName(item.worker),
            "Lokácia": item.location,
            "Číslo dielu": item.partNumber,
            "Batch": item.batch,
            "Množstvo": item.quantity,
            "Presný čas": new Date(item.timestamp).toLocaleTimeString('sk-SK')
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Inventúra");
        XLSX.writeFile(wb, `Inventura_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const toggleBatchMissing = () => {
        const newState = !isBatchMissing;
        setIsBatchMissing(newState);
        if (newState) {
            setBatch(`[${t('inv_label_missing').toUpperCase()}]`);
            setTimeout(() => quantityRef.current?.focus(), 10);
        } else {
            setBatch('');
            setTimeout(() => batchRef.current?.focus(), 10);
        }
    };

    const inputBaseClass = "w-full h-12 bg-gray-700 border border-gray-600 rounded-lg px-4 text-white text-base placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all font-mono uppercase";
    const dangerButtonClass = "bg-red-900/40 hover:bg-red-800 text-red-100 px-6 py-5 rounded-xl text-base font-black border-2 border-red-800/50 shadow-lg transition-all active:scale-95 uppercase tracking-wider flex items-center justify-center gap-2";

    return (
        <div className="max-w-4xl mx-auto space-y-8 pb-20 animate-fade-in">
            <div className="bg-gray-800 p-6 sm:p-8 rounded-xl shadow-lg border border-gray-700 relative overflow-hidden">
                {!activeInventoryTask ? (
                    <div className="flex flex-col items-center justify-center py-12 space-y-8">
                        <div className="text-center">
                            <h2 className="text-3xl font-bold text-white uppercase tracking-widest">{t('inv_not_started')}</h2>
                            <p className="text-gray-400 text-base mt-3">{t('inv_start_desc')}</p>
                        </div>
                        <button 
                            onClick={handleStartInventory}
                            className="bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-8 px-16 rounded-2xl shadow-[0_0_25px_rgba(65,105,225,0.4)] transition-all active:scale-95 uppercase tracking-[0.25em] text-2xl border-2 border-[#5a81f3]"
                        >
                            📋 {t('inv_start_btn')}
                        </button>
                    </div>
                ) : (
                    <>
                        <div className="flex justify-between items-start sm:items-center mb-10 border-b border-gray-700 pb-6">
                            <div>
                                <h1 className="text-4xl font-extrabold text-[#4169E1] uppercase tracking-widest leading-none">
                                    {t('tab_inventory')}
                                </h1>
                                <div className="flex gap-6 items-center mt-3">
                                    <span className="bg-[#4169E1]/20 text-[#4169E1] text-xs font-black px-3 py-1 rounded-md border border-[#4169E1]/40 animate-pulse uppercase">{t('inv_active_session')}</span>
                                    <p className="text-xs text-gray-500 uppercase font-mono">
                                        {t('inv_items_count')}: <span className="text-white font-bold">{(scannedItems || []).length}</span>
                                    </p>
                                </div>
                            </div>

                            <button 
                                onClick={handleCancelInventory}
                                className={dangerButtonClass.replace('px-6 py-5', 'px-5 py-3 text-xs')}
                            >
                                🛑 {t('inv_cancel_session')}
                            </button>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_location_label')}</label>
                                <input 
                                    ref={locationRef}
                                    type="text"
                                    value={location}
                                    onChange={(e) => setLocation(e.target.value.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && partRef.current?.focus()}
                                    placeholder="NAPR. MA123"
                                    className={inputBaseClass}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('part_number')}</label>
                                <PartNumberInput 
                                    inputRef={partRef}
                                    parts={parts}
                                    onPartSelect={(p) => setPartNumber(p || '')}
                                    onInputChange={(val) => setPartNumber(val.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && batchRef.current?.focus()}
                                    placeholder={t('part_placeholder')}
                                    value={partNumber}
                                    onRequestPart={onRequestPart}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('inv_batch_label')}</label>
                                <div className="flex gap-3">
                                    <input 
                                        ref={batchRef}
                                        type="text"
                                        inputMode="numeric"
                                        readOnly={isBatchMissing}
                                        value={batch}
                                        onChange={(e) => {
                                            if (!isBatchMissing) {
                                                const val = e.target.value.replace(/[^0-9]/g, '').slice(0, 7);
                                                setBatch(val);
                                            }
                                        }}
                                        maxLength={7}
                                        onKeyDown={(e) => e.key === 'Enter' && quantityRef.current?.focus()}
                                        placeholder={isBatchMissing ? '' : "489523"}
                                        className={`${inputBaseClass.replace('w-full', 'w-1/2')} ${isBatchMissing ? 'text-red-500 border-red-900/50 bg-red-900/10' : ''}`}
                                    />
                                    <button 
                                        type="button"
                                        onClick={toggleBatchMissing}
                                        className={`w-1/2 h-12 rounded-lg border-2 font-black uppercase text-xs text-white transition-all flex items-center justify-center gap-2 ${isBatchMissing ? 'bg-red-600 border-red-500 shadow-lg' : 'bg-[#4169E1]/20 border-[#4169E1] hover:bg-[#4169E1]/40'}`}
                                    >
                                        🏷️ {t('inv_label_missing')}
                                    </button>
                                </div>
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('quantity')}</label>
                                <input 
                                    ref={quantityRef}
                                    type="text"
                                    inputMode="decimal"
                                    value={quantity}
                                    onChange={(e) => setQuantity(e.target.value.replace(/[^0-9.,]/g, '').slice(0, 7))}
                                    maxLength={7}
                                    onKeyDown={(e) => e.key === 'Enter' && handleAddItem()}
                                    placeholder="0"
                                    className={`${inputBaseClass} font-black text-lg`}
                                />
                            </div>
                        </div>

                        <button 
                            onClick={handleAddItem}
                            className="w-full mt-10 bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-6 rounded-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest text-xl border-2 border-[#5a81f3]"
                        >
                            {t('inv_add_btn')}
                        </button>
                    </>
                )}
            </div>

            {activeInventoryTask && (
                <div className="bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                    <div className="p-5 sm:p-8 border-b border-gray-700 bg-gray-900/50 flex flex-col sm:row justify-between items-center gap-8">
                        <div className="flex items-center gap-6">
                            <h3 className="text-gray-400 font-black uppercase text-base tracking-[0.2em] leading-none">
                                {t('inv_list_title')}
                            </h3>
                            <span className="bg-[#4169E1]/20 text-white border-2 border-[#4169E1] text-2xl px-5 py-2 rounded-xl font-black font-mono leading-none shadow-lg">
                                {(scannedItems || []).length}
                            </span>
                        </div>
                        <div className="flex flex-wrap w-full sm:w-auto gap-4">
                            <button 
                                onClick={handleClearAll} 
                                className={dangerButtonClass}
                            >
                                {language === 'sk' ? 'Zmazať všetko' : 'Clear all'}
                            </button>
                            <button 
                                onClick={handleExportAndFinish}
                                className="flex-1 sm:flex-none bg-green-700 hover:bg-green-600 text-white px-10 py-5 rounded-xl text-lg font-black shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 border-2 border-green-500 uppercase tracking-widest"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                </svg>
                                {t('inv_export_finish')}
                            </button>
                        </div>
                    </div>

                    <div className="overflow-x-auto custom-scrollbar">
                        <table className="w-full text-left text-base border-collapse">
                            <thead className="bg-gray-900/30 text-gray-500 text-xs font-black uppercase tracking-widest border-b border-gray-700">
                                <tr>
                                    <th className="py-5 px-6">{language === 'sk' ? 'Čas' : 'Time'}</th>
                                    <th className="py-5 px-6">{t('inv_location_label')}</th>
                                    <th className="py-5 px-6">{t('part_number')}</th>
                                    <th className="py-5 px-6">Batch</th>
                                    <th className="py-5 px-6 text-right">{t('quantity')}</th>
                                    <th className="py-5 px-6 text-center"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700/50">
                                {scannedItems && scannedItems.length > 0 ? (
                                    scannedItems.map(item => (
                                        <tr key={item.id} className="text-gray-300 hover:bg-gray-700/30 transition-colors group">
                                            <td className="py-5 px-6 text-xs text-gray-500 font-mono whitespace-nowrap">{new Date(item.timestamp).toLocaleTimeString('sk-SK')}</td>
                                            <td className="py-5 px-6 font-mono font-bold text-[#4169E1] text-lg">{item.location}</td>
                                            <td className="py-5 px-6 font-mono text-white text-base">{item.partNumber}</td>
                                            <td className={`py-5 px-6 font-mono text-base ${item.batch.includes('[') ? 'text-red-500 font-bold' : 'text-gray-500'}`}>
                                                {item.batch || '-'}
                                            </td>
                                            <td className="py-5 px-6 font-black text-white text-right font-mono text-xl">{item.quantity}</td>
                                            <td className="py-5 px-6 text-center w-24">
                                                <button 
                                                    onClick={() => handleDeleteItem(item.id)} 
                                                    className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/30 text-red-500 hover:bg-red-800 hover:text-white border border-red-800/50 transition-all active:scale-90"
                                                >
                                                    <TrashIcon className="w-8 h-8" />
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr><td colSpan={6} className="py-16 text-center text-gray-600 italic font-bold text-lg">{t('inv_empty_list')}</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {confirmModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))}>
                    <div className="bg-gray-800 border-2 border-slate-700 rounded-2xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                        <div className="text-center mb-8">
                            <h3 className={`text-2xl font-black mb-3 uppercase tracking-tighter ${confirmModal.type === 'danger' ? 'text-red-500' : 'text-amber-500'}`}>
                                {confirmModal.title}
                            </h3>
                            <div className="text-gray-300 text-base leading-relaxed">
                                {confirmModal.message}
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))} className="flex-1 py-4 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-xs">
                                {t('btn_cancel')}
                            </button>
                            <button onClick={confirmModal.onConfirm} className={`flex-1 py-4 text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs border-2 ${confirmModal.type === 'danger' ? 'bg-red-600 hover:bg-red-700 border-red-500' : 'bg-amber-600 hover:bg-amber-700 border-amber-500'}`}>
                                {t('btn_confirm')}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default InventoryTab;

import React, { useState, useMemo } from 'react';
import { Task, UserData, MapSector, DBItem, SystemConfig, MapObstacle } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { COLOR_MAP } from '../../constants/uiConstants';
import { findAStarPath } from '../../utils/pathfinding';

interface MapVisualizationTabProps {
  tasks: Task[];
  draftTasks: Task[];
  fetchSanons: () => Promise<any[]>;
  users: UserData[];
  mapSectors: MapSector[];
  workplaces: DBItem[];
  logisticsOperations: DBItem[];
  mapObstacles: MapObstacle[];
  systemConfig: SystemConfig;
  resolveName: (username?: string | null) => string;
}

interface Point { x: number; y: number; label: string; type: 'wp' | 'sector' | 'log'; id: string; color?: string }
interface RouteSegment { path: {x: number, y: number}[]; worker: string; isTransit: boolean; taskType: 'prod' | 'log' }

const MapVisualizationTab: React.FC<MapVisualizationTabProps> = ({
  tasks, draftTasks, fetchSanons, users, mapSectors, workplaces, logisticsOperations, mapObstacles = [], systemConfig, resolveName
}) => {
  const { t } = useLanguage();

  const [dateFrom, setDateFrom] = useState(new Date().toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);
  const [selectedWorkers, setSelectedWorkers] = useState<string[]>([]);
  const [allData, setAllData] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleLoadMap = async () => {
    setIsLoading(true);
    try {
        const sanons = await fetchSanons();
        const combined: Task[] = [...tasks, ...draftTasks];
        sanons.forEach(s => { if (s.tasks) combined.push(...s.tasks); });
        const startTs = new Date(dateFrom).setHours(0,0,0,0);
        const endTs = new Date(dateTo).setHours(23,59,59,999);
        const filtered = combined.filter(t => {
            const ts = t.completedAt || t.createdAt || 0;
            return ts >= startTs && ts <= endTs && t.isDone;
        });
        const uniqueMap = new Map();
        filtered.forEach(t => uniqueMap.set(t.id, t));
        setAllData(Array.from(uniqueMap.values()));
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  const { segments, nodes, obstacles, viewBox } = useMemo(() => {
    const pointsMap = new Map<string, Point>();
    workplaces.forEach(w => pointsMap.set(`wp_${w.value}`, { x: w.coordX || 0, y: w.coordY || 0, label: w.value, type: 'wp', id: w.id }));
    logisticsOperations.forEach(l => pointsMap.set(`log_${l.value}`, { x: l.coordX || 0, y: l.coordY || 0, label: l.value, type: 'log', id: l.id }));
    mapSectors.forEach(s => pointsMap.set(`sector_${s.id}`, { x: s.coordX || 0, y: s.coordY || 0, label: s.name, type: 'sector', id: s.id, color: s.color }));

    const allNodes = Array.from(pointsMap.values());
    if (allNodes.length === 0 && mapObstacles.length === 0) {
        return { segments: [], nodes: [], obstacles: [], viewBox: "0 0 1000 1000" };
    }

    const nodeXs = allNodes.length > 0 ? allNodes.map(p => p.x) : [0, 1000];
    const nodeYs = allNodes.length > 0 ? allNodes.map(p => p.y) : [0, 1000];
    const minX = Math.min(...nodeXs, ...mapObstacles.flatMap(o => [o.x, o.x + o.w])) - 100;
    const minY = Math.min(...nodeYs, ...mapObstacles.flatMap(o => [o.y, o.y + o.h])) - 100;
    const maxX = Math.max(...nodeXs, ...mapObstacles.flatMap(o => [o.x, o.x + o.w])) + 100;
    const maxY = Math.max(...nodeYs, ...mapObstacles.flatMap(o => [o.y, o.y + o.h])) + 100;

    const workerSegments: RouteSegment[] = [];
    const grouped = new Map<string, Task[]>();
    const filteredByWorker = selectedWorkers.length > 0 ? allData.filter(t => selectedWorkers.includes(t.completedBy || '')) : allData;

    filteredByWorker.forEach(t => {
        const worker = t.completedBy || 'Unknown';
        if (!grouped.has(worker)) grouped.set(worker, []);
        grouped.get(worker)!.push(t);
    });

    grouped.forEach((workerTasks, worker) => {
        const sorted = [...workerTasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));
        let prevEnd: Point | null = null;
        sorted.forEach(task => {
            let startPoint: Point | null = null;
            let endPoint: Point | null = null;
            if (task.isLogistics) {
                const op = pointsMap.get(`log_${task.workplace}`);
                startPoint = pointsMap.get(`sector_${task.sourceSectorId}`) || op || null;
                endPoint = pointsMap.get(`sector_${task.targetSectorId}`) || op || null;
            } else {
                startPoint = pointsMap.get(`sector_${task.pickedFromSectorId}`) || null;
                endPoint = pointsMap.get(`wp_${task.workplace}`) || null;
            }
            if (startPoint && endPoint) {
                if (prevEnd) {
                    const transitPath = findAStarPath(prevEnd, startPoint, mapObstacles);
                    if (transitPath.length > 0) workerSegments.push({ path: transitPath, worker, isTransit: true, taskType: task.isLogistics ? 'log' : 'prod' });
                }
                const workPath = findAStarPath(startPoint, endPoint, mapObstacles);
                if (workPath.length > 0) workerSegments.push({ path: workPath, worker, isTransit: false, taskType: task.isLogistics ? 'log' : 'prod' });
                prevEnd = endPoint;
            }
        });
    });

    return { segments: workerSegments, nodes: allNodes, obstacles: mapObstacles, viewBox: `${minX} ${minY} ${maxX - minX} ${maxY - minY}` };
  }, [allData, selectedWorkers, workplaces, logisticsOperations, mapSectors, mapObstacles]);

  const generatePathData = (path: {x: number, y: number}[]) => {
      if (path.length === 0) return "";
      const simplified = [path[0]];
      for (let i = 1; i < path.length - 1; i++) {
          const prev = path[i-1], curr = path[i], next = path[i+1];
          if (!((prev.x === curr.x && curr.x === next.x) || (prev.y === curr.y && curr.y === next.y))) simplified.push(curr);
      }
      if (path.length > 1) simplified.push(path[path.length - 1]);
      return `M ${simplified[0].x} ${simplified[0].y} ` + simplified.slice(1).map(p => `L ${p.x} ${p.y}`).join(' ');
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in px-2 md:px-0">
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-5 shadow-xl">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="md:col-span-1 space-y-4">
                    <h3 className="text-sm font-black text-amber-500 uppercase tracking-widest border-b border-amber-900/30 pb-2">{t('map_anal_period')}</h3>
                    <div className="grid grid-cols-2 gap-2">
                        <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white" />
                        <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-white" />
                    </div>
                    <button onClick={handleLoadMap} disabled={isLoading} className="w-full h-12 bg-amber-600 hover:bg-amber-500 text-white font-black rounded-xl uppercase text-xs tracking-widest shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 border-2 border-amber-500 disabled:opacity-50">
                        {isLoading ? '⏳ ...' : '🔄 ' + t('map_load_btn')}
                    </button>
                </div>
                <div className="md:col-span-2 space-y-4 border-l border-slate-800 pl-6">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">{t('map_filter_workers')}</h3>
                    <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto custom-scrollbar">
                        {users.map(u => (
                            <button key={u.username} onClick={() => setSelectedWorkers(prev => prev.includes(u.username) ? prev.filter(w => w !== u.username) : [...prev, u.username])} className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedWorkers.includes(u.username) ? 'bg-teal-500 border-teal-400 text-white shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}>{u.nickname || u.username}</button>
                        ))}
                    </div>
                </div>
                <div className="md:col-span-1 space-y-4 border-l border-slate-800 pl-6 text-center">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest border-b border-slate-800 pb-2">{t('top_lists_sheet_name')}</h3>
                    <div className="flex flex-col gap-2 items-start text-[10px] font-black uppercase tracking-widest text-slate-500">
                        <div className="flex items-center gap-2"><div className="w-3 h-1 bg-teal-500 rounded"></div> {t('map_legend_prod')}</div>
                        <div className="flex items-center gap-2"><div className="w-3 h-1 bg-sky-500 rounded"></div> {t('map_legend_log')}</div>
                        <div className="flex items-center gap-2"><div className="w-3 h-1 bg-slate-600 border-dashed border"></div> {t('map_legend_transit')}</div>
                    </div>
                </div>
            </div>
        </div>

        <div className="bg-slate-900 border-2 border-slate-800 rounded-3xl shadow-2xl overflow-hidden relative min-h-[650px] flex flex-col group">
            {isLoading && (
                <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-50 flex flex-col items-center justify-center gap-4">
                    <div className="w-16 h-16 border-4 border-amber-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-amber-500 font-black animate-pulse uppercase tracking-[0.4em] text-lg">{t('map_loading')}</p>
                </div>
            )}
            <div className="flex-grow relative overflow-hidden bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-800/20 via-slate-900 to-slate-950">
                <svg viewBox={viewBox} className="w-full h-full min-h-[650px]" xmlns="http://www.w3.org/2000/svg">
                    <defs>
                        <pattern id="grid5m" width="50" height="50" patternUnits="userSpaceOnUse"><path d="M 50 0 L 0 0 0 50" fill="none" stroke="white" strokeWidth="1" strokeOpacity="0.05" /></pattern>
                        <pattern id="grid1m" width="10" height="10" patternUnits="userSpaceOnUse"><path d="M 10 0 L 0 0 0 10" fill="none" stroke="white" strokeWidth="0.5" strokeOpacity="0.02" /></pattern>
                        <pattern id="hatch" patternUnits="userSpaceOnUse" width="10" height="10"><path d="M-1,1 l2,-2 M0,10 l10,-10 M9,11 l2,-2" stroke="white" strokeWidth="1" strokeOpacity="0.1" /></pattern>
                    </defs>
                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid1m)" />
                    <rect width="10000" height="10000" x="-5000" y="-5000" fill="url(#grid5m)" />
                    {obstacles.map((o, idx) => (
                        <g key={o.id || idx}>
                            <rect x={o.x} y={o.y} width={o.w} height={o.h} fill="#1e293b" stroke="#334155" strokeWidth="2" rx="4" />
                            <rect x={o.x} y={o.y} width={o.w} height={o.h} fill="url(#hatch)" rx="4" />
                            {o.w > 40 && <text x={o.x + o.w/2} y={o.y + o.h/2} textAnchor="middle" dominantBaseline="middle" className="fill-slate-600 text-[10px] font-black uppercase tracking-widest pointer-events-none">{o.name}</text>}
                        </g>
                    ))}
                    {segments.map((s, i) => (
                        <path key={`${s.isTransit ? 'tr' : 'ride'}-${i}`} d={generatePathData(s.path)} fill="none" stroke={s.isTransit ? '#475569' : (s.taskType === 'prod' ? '#14b8a6' : '#0ea5e9')} strokeWidth={s.isTransit ? 1.5 : 3.5} strokeDasharray={s.isTransit ? '6 4' : 'none'} strokeOpacity={s.isTransit ? 0.4 : 0.8} strokeLinecap="round" strokeLinejoin="round" />
                    ))}
                    {nodes.map(node => {
                        const isSector = node.type === 'sector';
                        const colorValue = isSector ? (COLOR_MAP[node.color as keyof typeof COLOR_MAP]?.replace('bg-', '') || 'pink-500') : 'blue-500';
                        return (
                            <g key={node.id} transform={`translate(${node.x}, ${node.y})`} className="group/node">
                                {isSector ? <rect x="-14" y="-14" width="28" height="28" rx="8" fill="currentColor" className={`text-${colorValue} opacity-20 border-2 border-current group-hover/node:opacity-50 transition-all`} /> : <circle r="10" fill="#0f172a" stroke={node.type === 'wp' ? '#3b82f6' : '#0ea5e9'} strokeWidth="3" />}
                                <text y={isSector ? -32 : -25} textAnchor="middle" fill="white" className="text-[10px] font-black uppercase tracking-widest opacity-0 group-hover/node:opacity-100 transition-opacity pointer-events-none drop-shadow-md bg-black/50 px-1">{node.label}</text>
                            </g>
                        );
                    })}
                </svg>
                <div className="absolute bottom-6 right-6 bg-slate-900/60 backdrop-blur-md border border-slate-700 p-4 rounded-2xl pointer-events-none shadow-2xl">
                     <div className="flex flex-col items-center gap-2">
                        <div className="w-[100px] h-3 border-x-2 border-slate-400 relative"><div className="absolute top-1/2 left-0 right-0 h-0.5 bg-slate-400 -translate-y-1/2"></div></div>
                        <span className="text-[10px] font-black text-white uppercase tracking-widest">{t('map_scale_label')}</span>
                     </div>
                </div>
            </div>
        </div>
    </div>
  );
};

export default MapVisualizationTab;

import React, { useState, useMemo, useEffect } from 'react';
import { Task, UserData, MapSector } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

declare var XLSX: any;

interface TransactionLogTabProps {
  tasks: Task[]; // Živé úlohy
  draftTasks: Task[]; // Draft (denný)
  fetchSanons: () => Promise<any[]>; // Archív
  users: UserData[];
  mapSectors: MapSector[];
  resolveName: (username?: string | null) => string;
}

const TransactionLogTab: React.FC<TransactionLogTabProps> = ({ 
  tasks, draftTasks, fetchSanons, users, mapSectors, resolveName 
}) => {
  const { t, language } = useLanguage();

  // Filtre
  const [dateFrom, setDateFrom] = useState(new Date().toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);
  const [timeFrom, setTimeFrom] = useState('06:00');
  const [timeTo, setTimeTo] = useState('18:00');
  const [selectedUser, setSelectedUser] = useState<string>('');
  const [searchQuery, setSearchQuery] = useState('');

  // Dáta
  const [historicalData, setHistoricalData] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Načítanie historických dát pri zmene dátumu
  useEffect(() => {
    const loadHistory = async () => {
      const today = new Date().toISOString().split('T')[0];
      if (dateFrom === today && dateTo === today) {
          setHistoricalData([]);
          return;
      }

      setIsLoading(true);
      try {
        const sanons = await fetchSanons();
        const relevantTasks: Task[] = [];
        sanons.forEach(sanon => {
           if (sanon.tasks && Array.isArray(sanon.tasks)) {
               relevantTasks.push(...sanon.tasks);
           }
        });
        setHistoricalData(relevantTasks);
      } catch (e) {
        console.error("Failed to load archive for logs", e);
      } finally {
        setIsLoading(false);
      }
    };
    loadHistory();
  }, [dateFrom, dateTo, fetchSanons]);

  const resolveSector = (sectorId?: string) => {
      if (!sectorId) return '';
      const s = mapSectors.find(x => x.id === sectorId);
      return s ? s.name : sectorId;
  };

  const filteredLogs = useMemo(() => {
    const startTs = new Date(dateFrom).setHours(0,0,0,0);
    const endTs = new Date(dateTo).setHours(23,59,59,999);

    const allSource = [...tasks, ...draftTasks, ...historicalData];
    const unique = new Map();
    allSource.forEach(t => unique.set(t.id, t));
    const combined = Array.from(unique.values()) as Task[];

    return combined.filter(task => {
        const taskTime = task.completedAt || task.createdAt || 0;
        if (taskTime < startTs || taskTime > endTs) return false;

        const dateObj = new Date(taskTime);
        const taskHHMM = dateObj.getHours().toString().padStart(2, '0') + ':' + dateObj.getMinutes().toString().padStart(2, '0');
        if (taskHHMM < timeFrom || taskHHMM > timeTo) return false;

        if (selectedUser) {
            if (task.completedBy !== selectedUser && task.createdBy !== selectedUser) return false;
        }

        if (searchQuery) {
            const q = searchQuery.toLowerCase();
            const content = `${task.partNumber} ${task.workplace} ${task.note} ${resolveName(task.completedBy)}`.toLowerCase();
            if (!content.includes(q)) return false;
        }

        return true;
    }).sort((a,b) => (b.completedAt || b.createdAt || 0) - (a.completedAt || a.createdAt || 0));
  }, [tasks, draftTasks, historicalData, dateFrom, dateTo, timeFrom, timeTo, selectedUser, searchQuery, resolveName]);

  const handleExport = () => {
      if (filteredLogs.length === 0) {
          alert(t('logs_no_data'));
          return;
      }

      const exportData = filteredLogs.map(t => {
          let sourceVal = '';
          let targetVal = '';

          if (t.isLogistics) {
                const op = (t.workplace || '').toUpperCase();
                const isUnloading = op.includes('VYKL') || op.includes('UNLOAD') || op.includes('PRÍJEM');
                const isLoading = op.includes('NAKL') || op.includes('LOAD') || op.includes('EXPED');

                if (isUnloading) {
                    sourceVal = t.note || 'EXT';
                    targetVal = resolveSector(t.targetSectorId) || (language === 'sk' ? 'PRÍJEM' : 'INBOUND');
                } else if (isLoading) {
                    sourceVal = resolveSector(t.sourceSectorId) || (language === 'sk' ? 'SKLAD' : 'WAREHOUSE');
                    targetVal = t.note || 'EXT';
                } else {
                    sourceVal = resolveSector(t.sourceSectorId) || '';
                    targetVal = resolveSector(t.targetSectorId) || '';
                }
          } else {
              sourceVal = resolveSector(t.pickedFromSectorId) || (language === 'sk' ? 'SKLAD' : 'WAREHOUSE');
              targetVal = t.workplace || '';
          }

          return {
              [language === 'sk' ? 'ID Transakcie' : 'Transaction ID']: t.id,
              [language === 'sk' ? 'Dátum' : 'Date']: new Date(t.completedAt || t.createdAt || 0).toLocaleDateString('sk-SK'),
              [language === 'sk' ? 'Čas' : 'Time']: new Date(t.completedAt || t.createdAt || 0).toLocaleTimeString('sk-SK'),
              [language === 'sk' ? 'Operátor' : 'Operator']: resolveName(t.completedBy || t.createdBy),
              [t('part_number')]: t.partNumber,
              [t('quantity')]: t.quantity,
              [language === 'sk' ? 'Jednotka' : 'Unit']: t.quantityUnit,
              [t('excel_col_source')]: sourceVal,
              [t('excel_col_target')]: targetVal,
              [t('log_operation')]: t.isLogistics ? 'LOGISTIKA' : 'VÝROBA',
              [language === 'sk' ? 'Operácia/Pracovisko' : 'Workplace']: t.workplace,
              [t('status_label')]: t.auditResult ? `AUDIT ${t.auditResult}` : (t.isMissing ? (language === 'sk' ? 'CHÝBA' : 'MISSING') : 'OK')
          };
      });

      const ws = XLSX.utils.json_to_sheet(exportData);
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "TRANSAKCIE_LOG");
      XLSX.writeFile(wb, `LOG_EXPORT_${dateFrom}_${timeFrom.replace(':','')}-${timeTo.replace(':','')}.xlsx`);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in px-2 md:px-0">

        {/* CONTROL PANEL */}
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-5 shadow-xl">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 border-b border-slate-800 pb-4 gap-4">
                <h2 className="text-xl font-black text-cyan-400 uppercase tracking-widest flex items-center gap-2">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg>
                    {t('logs_title')}
                </h2>
                <div className="flex gap-2 w-full md:w-auto">
                    <button onClick={handleExport} className="flex-1 md:flex-none bg-green-700 hover:bg-green-600 text-white px-6 py-2 rounded-xl font-bold text-xs uppercase tracking-widest transition-all shadow-lg border border-green-500 flex items-center justify-center gap-2">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                        EXPORT RAW DATA
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                <div>
                    <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">{language === 'sk' ? 'Dátum Od' : 'Date From'}</label>
                    <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-white text-xs focus:border-cyan-500 outline-none" />
                </div>
                <div>
                    <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">{language === 'sk' ? 'Dátum Do' : 'Date To'}</label>
                    <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-white text-xs focus:border-cyan-500 outline-none" />
                </div>
                <div>
                    <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">{language === 'sk' ? 'Časové Okno (Zmena)' : 'Time window'}</label>
                    <div className="flex gap-1">
                        <input type="time" value={timeFrom} onChange={e => setTimeFrom(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-2 py-2 text-white text-xs focus:border-cyan-500 outline-none text-center" />
                        <input type="time" value={timeTo} onChange={e => setTimeTo(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-2 py-2 text-white text-xs focus:border-cyan-500 outline-none text-center" />
                    </div>
                </div>
                <div>
                    <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">{language === 'sk' ? 'Užívateľ' : 'User'}</label>
                    <select value={selectedUser} onChange={e => setSelectedUser(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-white text-xs focus:border-cyan-500 outline-none">
                        <option value="">{t('filter_all').toUpperCase()}</option>
                        {users.map(u => <option key={u.username} value={u.username}>{u.nickname || u.username}</option>)}
                    </select>
                </div>
                <div>
                    <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">{language === 'sk' ? 'Hľadať (Part No)' : 'Search'}</label>
                    <input type="text" value={searchQuery} onChange={e => setSearchQuery(e.target.value)} placeholder="..." className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-white text-xs focus:border-cyan-500 outline-none uppercase font-mono" />
                </div>
            </div>
        </div>

        {/* DATA GRID */}
        <div className="bg-slate-900 border border-slate-800 rounded-2xl shadow-xl overflow-hidden min-h-[400px]">
            {isLoading ? (
                <div className="flex items-center justify-center h-64">
                    <p className="text-cyan-500 font-black animate-pulse uppercase tracking-widest">{t('map_loading')}</p>
                </div>
            ) : (
                <div className="overflow-x-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                        <thead className="bg-slate-950 text-slate-500 text-[10px] font-black uppercase tracking-[0.1em] sticky top-0 z-10 shadow-sm">
                            <tr>
                                <th className="p-4 w-32">{t('logs_th_datetime')}</th>
                                <th className="p-4 w-32">{t('logs_th_user')}</th>
                                <th className="p-4 w-40">{t('logs_th_part')}</th>
                                <th className="p-4 w-24 text-right">{t('logs_th_qty')}</th>
                                <th className="p-4 w-48">{t('logs_th_movement')}</th>
                                <th className="p-4 w-32">{t('logs_th_status')}</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-800/50 text-xs font-mono text-slate-300">
                            {filteredLogs.length > 0 ? (
                                filteredLogs.map(item => {
                                    let fromStr = '';
                                    let toStr = '';
                                    if (item.isLogistics) {
                                        const op = (item.workplace || '').toUpperCase();
                                        if (op.includes('VYKL') || op.includes('UNLOAD')) {
                                            fromStr = item.note || 'EXT'; toStr = resolveSector(item.targetSectorId) || (language === 'sk' ? 'PRÍJEM' : 'INBOUND');
                                        } else if (op.includes('NAKL') || op.includes('LOAD')) {
                                            fromStr = resolveSector(item.sourceSectorId) || (language === 'sk' ? 'SKLAD' : 'WAREHOUSE'); toStr = item.note || 'EXT';
                                        } else {
                                            fromStr = resolveSector(item.sourceSectorId) || '?'; toStr = resolveSector(item.targetSectorId) || '?';
                                        }
                                    } else {
                                        fromStr = resolveSector(item.pickedFromSectorId) || (language === 'sk' ? 'SKLAD' : 'WAREHOUSE');
                                        toStr = item.workplace || (language === 'sk' ? 'VÝROBA' : 'PRODUCTION');
                                    }

                                    const ts = item.completedAt || item.createdAt || 0;
                                    return (
                                        <tr key={item.id} className="hover:bg-cyan-900/10 transition-colors">
                                            <td className="p-4 border-r border-slate-800/50">
                                                <div className="font-bold text-slate-200">{new Date(ts).toLocaleDateString('sk-SK')}</div>
                                                <div className="text-[10px] text-slate-500">{new Date(ts).toLocaleTimeString('sk-SK')}</div>
                                            </td>
                                            <td className="p-4 border-r border-slate-800/50 font-bold text-cyan-400">
                                                {resolveName(item.completedBy || item.createdBy)}
                                            </td>
                                            <td className="p-4 border-r border-slate-800/50">
                                                <span className="bg-slate-800 px-2 py-1 rounded text-white font-bold">{item.partNumber}</span>
                                            </td>
                                            <td className="p-4 text-right border-r border-slate-800/50">
                                                <span className="font-black text-white">{item.quantity}</span> <span className="text-[10px] text-slate-500">{item.quantityUnit}</span>
                                            </td>
                                            <td className="p-4 border-r border-slate-800/50">
                                                <div className="flex items-center gap-2">
                                                    <span className="text-slate-400 truncate max-w-[80px]" title={fromStr}>{fromStr}</span>
                                                    <span className="text-cyan-600">→</span>
                                                    <span className="text-white font-bold truncate max-w-[100px]" title={toStr}>{toStr}</span>
                                                </div>
                                            </td>
                                            <td className="p-4 text-center">
                                                {item.auditResult === 'NOK' ? (
                                                    <span className="text-red-500 font-black bg-red-500/10 px-2 py-1 rounded">AUDIT NOK</span>
                                                ) : item.isMissing ? (
                                                    <span className="text-orange-500 font-black">{language === 'sk' ? 'CHÝBA' : 'MISSING'}</span>
                                                ) : (
                                                    <span className="text-green-500 font-black text-[10px]">OK</span>
                                                )}
                                            </td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={6} className="py-20 text-center text-slate-600 italic font-bold uppercase tracking-widest">
                                        {t('logs_no_data')}
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            )}
        </div>

        <div className="text-center text-[10px] text-slate-600 font-bold uppercase tracking-widest">
            {language === 'sk' ? `Zobrazených ${filteredLogs.length} záznamov` : `Displaying ${filteredLogs.length} records`}
        </div>
    </div>
  );
};

export default TransactionLogTab;

import React, { useState } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  getDocs, 
  writeBatch,
  doc,
  getDoc,
  updateDoc
} from 'firebase/firestore';
import { useLanguage } from '../LanguageContext';
import { MapSector } from '../../types/appTypes';

declare var XLSX: any;

interface YearlyClosingProps {
  resolveName: (username?: string | null) => string;
  fetchSanons: () => Promise<any[]>;
  mapSectors: MapSector[];
}

const YearlyClosing: React.FC<YearlyClosingProps> = ({ resolveName, fetchSanons, mapSectors }) => {
  const { t, language } = useLanguage();
  const [isExporting, setIsExporting] = useState(false);
  const [isResetting, setIsResetting] = useState(false);
  const [hasExported, setHasExported] = useState(false);
  const [progress, setProgress] = useState('');

  const formatDate = (ts?: number) => {
    if (!ts) return '';
    const d = new Date(ts);
    return d.toLocaleDateString('sk-SK', { day: '2-digit', month: '2-digit', year: 'numeric' });
  };

  const formatTime = (ts?: number) => {
    if (!ts) return '';
    const d = new Date(ts);
    return d.toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' });
  };

  const formatDateTime = (ts?: number) => {
    if (!ts) return '';
    return `${formatDate(ts)} ${formatTime(ts)}`;
  };

  const resolveSectorName = (sectorId?: string) => {
      if (!sectorId) return '';
      const sector = mapSectors.find(s => s.id === sectorId);
      return sector ? sector.name : sectorId;
  };

  const fetchYearlyData = async () => {
    setIsExporting(true);
    setProgress(t('closing_preparing'));

    const allTasks: any[] = [];
    const currentYear = new Date().getFullYear();

    try {
      setProgress(t('closing_fetching_live'));
      const snapTasks = await getDocs(collection(db, 'tasks'));
      snapTasks.forEach(d => allTasks.push({ id: d.id, ...d.data() }));

      setProgress(t('closing_fetching_draft'));
      const draftSnap = await getDoc(doc(db, 'settings', 'draft'));
      if (draftSnap.exists()) {
          (draftSnap.data().data || []).forEach((t: any) => allTasks.push(t));
      }

      setProgress(t('closing_fetching_buckets'));
      const sanons = await fetchSanons();

      sanons.forEach(sanon => {
          if (sanon.tasks && Array.isArray(sanon.tasks)) {
              allTasks.push(...sanon.tasks);
          }
      });

      if (allTasks.length === 0) {
        alert(t('closing_no_data'));
        setIsExporting(false);
        return;
      }

      const excelData = allTasks.map(item => {
        let searchResult = '';
        if (item.searchedBy) {
          if (item.searchExhausted || item.auditResult) {
            searchResult = t('no');
          } else if (item.isMissing === false) {
            searchResult = t('yes');
          } else {
            searchResult = language === 'sk' ? 'Prebieha' : 'In Progress';
          }
        }

        let statusText = t('status_open');
        if (item.status === 'incorrectly_entered') {
            statusText = t('status_incorrect');
        } else if (item.auditResult) {
            statusText = language === 'sk' ? 'Auditované' : 'Audited';
        } else if (item.isDone) {
            statusText = t('status_completed');
        }

        let sourceVal = '';
        let targetVal = '';

        if (item.isLogistics) {
            const op = (item.workplace || '').toUpperCase();
            const isUnloading = op.includes('VYKL') || op.includes('UNLOAD') || op.includes('PRÍJEM') || op.includes('INBOUND');
            const isLoading = op.includes('NAKL') || op.includes('LOAD') || op.includes('EXPED') || op.includes('OUTBOUND');

            if (isUnloading) {
                 sourceVal = item.note || 'EXT';
                 targetVal = resolveSectorName(item.targetSectorId) || (language === 'sk' ? 'PRÍJEM' : 'INBOUND');
            } else if (isLoading) {
                 sourceVal = resolveSectorName(item.sourceSectorId) || (language === 'sk' ? 'SKLAD' : 'WAREHOUSE');
                 targetVal = item.note || 'EXT';
            } else {
                 sourceVal = resolveSectorName(item.sourceSectorId) || '';
                 targetVal = resolveSectorName(item.targetSectorId) || '';
            }
        } else {
            sourceVal = resolveSectorName(item.pickedFromSectorId) || '';
            targetVal = item.workplace || '';
        }

        return {
          [t('excel_col_date_added')]: formatDate(item.createdAt),
          [t('excel_col_time_added')]: formatTime(item.createdAt),
          [t('excel_col_creator')]: resolveName(item.createdBy),
          [t('excel_col_part')]: item.partNumber || '',
          [t('excel_col_workplace')]: item.workplace || '',
          [t('excel_col_plate')]: item.isLogistics ? (item.note || '') : '',
          [t('logs_th_qty')]: item.quantity || '',
          [language === 'sk' ? 'Jednotka' : 'Unit']: item.quantityUnit || '',
          [t('excel_col_note')]: !item.isLogistics ? (item.note || '') : '',
          [t('excel_col_worker')]: resolveName(item.completedBy),
          [t('excel_col_date_done')]: formatDate(item.completedAt),
          [t('excel_col_time_done')]: formatTime(item.completedAt),
          [t('excel_col_status')]: statusText,
          [t('excel_col_miss_reporter')]: resolveName(item.missingReportedBy),
          [t('excel_col_miss_reason')]: item.missingReason || '',
          [t('excel_col_miss_time')]: item.missingReportedBy ? formatTime(item.completedAt || item.createdAt) : '',
          [t('excel_col_searcher')]: item.searchedBy || '',
          [t('excel_col_search_res')]: searchResult,
          [t('excel_col_audit_res')]: item.auditResult || '',
          [t('excel_col_audit_note')]: item.auditNote || '',
          [t('excel_col_auditor')]: resolveName(item.auditedBy) || item.auditBy || '',
          [t('excel_col_audit_datetime')]: formatDateTime(item.auditedAt ?? undefined),
          [t('excel_col_source')]: sourceVal,
          [t('excel_col_target')]: targetVal
        };
      });

      const ws = XLSX.utils.json_to_sheet(excelData);
      const wscols = Array(24).fill({wch: 20});
      ws['!cols'] = wscols;

      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "ROCNA_UZAVIERKA");
      XLSX.writeFile(wb, `KOMPLETNY_ARCHIV_${currentYear}_${new Date().getTime()}.xlsx`);

      setHasExported(true);
      setProgress(language === 'sk' ? 'Export úspešný!' : 'Export successful!');
    } catch (error) {
      console.error(error);
      alert('Chyba pri exporte.');
    } finally {
      setIsExporting(false);
    }
  };

  const handleReset = async () => {
    if (!hasExported) return;

    const confirm1 = window.confirm(language === 'sk' 
      ? "VAROVANIE: Chystáte sa definitívne vymazať VŠETKY úlohy a archívy z aktuálneho roku! Máte stiahnutú Excel zálohu?" 
      : "WARNING: You are about to permanently delete ALL tasks and archives from the current year! Do you have your Excel backup?");

    if (!confirm1) return;

    const confirm2 = window.confirm(language === 'sk'
      ? "Posledné varovanie: Táto akcia je nevratná. Pokračovať?"
      : "Final warning: This action is irreversible. Proceed?");

    if (!confirm2) return;

    setIsResetting(true);
    setProgress(language === 'sk' ? 'Premazávam databázu...' : 'Cleaning database...');

    try {
      await updateDoc(doc(db, 'settings', 'draft'), { data: [] });

      const sanonsToDelete = await fetchSanons();
      if (sanonsToDelete.length > 0) {
          const batch = writeBatch(db);
          let opCount = 0;
          for (const sanon of sanonsToDelete) {
              const sanonRef = doc(db, 'sanony', sanon.id);
              batch.delete(sanonRef);
              opCount++;
              if (opCount >= 498) { await batch.commit(); }
          }
          if (opCount > 0) await batch.commit();
      }

      const snapTasks = await getDocs(collection(db, 'tasks'));
      let batchTasks = writeBatch(db);
      let count = 0;
      for (const d of snapTasks.docs) {
        batchTasks.delete(d.ref);
        count++;
        if (count === 500) { await batchTasks.commit(); batchTasks = writeBatch(db); count = 0; }
      }
      if (count > 0) await batchTasks.commit();

      alert(language === 'sk' ? 'Systém bol úspešne zresetovaný.' : 'System successfully reset.');
      window.location.reload();
    } catch (error) {
      console.error(error);
      alert('Chyba pri čistení dát.');
    } finally {
      setIsResetting(false);
    }
  };

  return (
    <div className="bg-gray-800/40 border border-slate-700/50 rounded-2xl p-8 shadow-2xl backdrop-blur-sm animate-fade-in">
      <div className="flex items-center gap-4 mb-8">
        <div className="p-3 bg-rose-500/20 rounded-xl">
          <svg className="w-8 h-8 text-rose-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        </div>
        <div>
          <h3 className="text-2xl font-black text-white uppercase tracking-tighter">{t('closing_yearly_title')}</h3>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">{language === 'sk' ? 'Archivácia a čistenie systémových dát' : 'Archiving and data cleanup'}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-slate-950/40 p-6 rounded-2xl border border-white/5 space-y-4">
          <h4 className="text-sm font-black text-teal-400 uppercase tracking-widest">{t('closing_step1_title')}</h4>
          <p className="text-xs text-slate-400 leading-relaxed">
            {t('closing_step1_desc')}
          </p>
          <button 
            onClick={fetchYearlyData}
            disabled={isExporting || isResetting}
            className={`w-full py-4 rounded-xl font-black uppercase text-xs tracking-widest transition-all border-2 shadow-lg flex items-center justify-center gap-3 ${
              isExporting ? 'bg-gray-700 border-gray-600 text-gray-400 animate-pulse' : 'bg-teal-600 hover:bg-teal-500 text-white border-teal-500'
            }`}
          >
            {isExporting ? '...' : (
              <>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                {t('closing_step1_btn')}
              </>
            )}
          </button>
        </div>

        <div className="bg-slate-950/40 p-6 rounded-2xl border border-white/5 space-y-4">
          <h4 className="text-sm font-black text-rose-400 uppercase tracking-widest">{t('closing_step2_title')}</h4>
          <p className="text-xs text-slate-400 leading-relaxed">
            {t('closing_step2_desc')}
          </p>
          <button 
            onClick={handleReset}
            disabled={!hasExported || isResetting || isExporting}
            className={`w-full py-4 rounded-xl font-black uppercase text-xs tracking-widest transition-all border-2 shadow-lg flex items-center justify-center gap-3 ${
              !hasExported ? 'bg-gray-800 border-gray-700 text-gray-600 cursor-not-allowed' : 'bg-rose-600 hover:bg-rose-500 text-white border-rose-500'
            }`}
          >
            {isResetting ? '...' : (
              <>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                {t('closing_step2_btn')}
              </>
            )}
          </button>
        </div>
      </div>

      {progress && (
        <div className="mt-8 text-center animate-fade-in">
          <p className="text-xs font-mono font-bold text-amber-500 bg-amber-500/5 py-2 px-4 rounded-full inline-block border border-amber-500/20 uppercase tracking-widest">
            {progress}
          </p>
        </div>
      )}
    </div>
  );
};

